'use client';

import { useState } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { AuthService } from '@/services/auth.service';

export default function RegisterPage() {
    const router = useRouter();
    const [loading, setLoading] = useState(false);
    const [formData, setFormData] = useState({
        nombre: '',
        apellido: '',
        email: '',
        password: ''
    });
    const [error, setError] = useState<string | null>(null);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setFormData({
            ...formData,
            [e.target.name]: e.target.value
        });
    };

    const handleRegister = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError(null);

        try {
            const { data, error } = await AuthService.signUp(
                formData.email.trim(),
                formData.password,
                formData.nombre,
                formData.apellido
            );

            if (error) {
                setError(error.message);
            } else {
                // Determine next step based on auto-confirm status (usually check email)
                // For dev/test, if auto-confirm is on, we can login or redirect.
                // Assuming standard flow:
                if (data.user) {
                    // First time user -> Redirect to profile to complete data
                    router.push('/dashboard/profile');
                } else {
                    // Verify email case
                    alert('Revisa tu correo para confirmar la cuenta.');
                    router.push('/login');
                }
            }
        } catch (err: any) {
            setError('Ocurri├│ un error inesperado.');
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="glass-card p-8 rounded-[2rem] animate-in fade-in zoom-in duration-500 max-w-md w-full mx-auto">
            <div className="text-center mb-6">
                <h1 className="text-2xl font-black text-slate-800 mb-2">Comienza Gratis</h1>
                <p className="text-slate-500 text-sm font-medium">Crea tu cuenta y revoluciona tus clases</p>
            </div>

            {error && (
                <div className="bg-red-50 text-red-600 p-3 rounded-lg text-sm mb-4 text-center border border-red-100">
                    {error}
                </div>
            )}

            <form onSubmit={handleRegister} className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        {/* Manual label rendering since Input component might be custom and tricky to pass name prop if not standardized. 
                             Checking usage: Input has label prop. Let's start with standard HTML input attributes passed via ...props if supported.
                             Wait, I don't know the exact Input props interface. The file viewer showed: label, placeholder, required.
                             I will try to pass name and onChange. If it fails, I'll need to check Input definition.
                             Assuming Input component spreads props to underlying input.
                          */}
                        <Input
                            label="Nombre"
                            name="nombre"
                            placeholder="Juan"
                            required
                            value={formData.nombre}
                            onChange={handleChange}
                        />
                    </div>
                    <div>
                        <Input
                            label="Apellido"
                            name="apellido"
                            placeholder="P├®rez"
                            required
                            value={formData.apellido}
                            onChange={handleChange}
                        />
                    </div>
                </div>

                <Input
                    label="Email"
                    name="email"
                    type="email"
                    placeholder="profe@ejemplo.com"
                    icon="mail"
                    required
                    value={formData.email}
                    onChange={handleChange}
                />

                <Input
                    label="Contrase├▒a"
                    name="password"
                    type="password"
                    placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                    icon="lock"
                    required
                    value={formData.password}
                    onChange={handleChange}
                />

                <div className="flex items-start gap-3 mt-2">
                    <input type="checkbox" id="terms" className="mt-1 rounded border-slate-300 text-blue-600 focus:ring-blue-500" required />
                    <label htmlFor="terms" className="text-xs text-slate-500">
                        Acepto los <Link href="/terms" className="text-blue-600 font-bold hover:underline">T├®rminos y Condiciones</Link> y la Pol├¡tica de Privacidad.
                    </label>
                </div>

                <Button type="submit" isLoading={loading} className="w-full mt-4">
                    <span>Crear Cuenta</span>
                    <span className="material-symbols-rounded text-lg ml-2">rocket_launch</span>
                </Button>
            </form>

            <div className="mt-8 pt-6 border-t border-slate-100 text-center">
                <p className="text-sm font-medium text-slate-500">
                    ┬┐Ya tienes cuenta? {' '}
                    <Link href="/login" className="text-blue-600 font-bold hover:underline">
                        Inicia sesi├│n
                    </Link>
                </p>
            </div>
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import { AdminService, SystemStats } from '@/services/admin.service';
import { AuthService } from '@/services/auth.service';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { ProfileService } from '@/services/profile.service';

export default function AdminDashboardPage() {
    const router = useRouter();
    const [stats, setStats] = useState<SystemStats | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        checkAccessAndLoad();
    }, []);

    const checkAccessAndLoad = async () => {
        try {
            // 1. Check Auth & Role
            const { data, error: sessionError } = await AuthService.getSession();

            if (sessionError) {
                console.warn('Session error in admin page:', sessionError);
                router.push('/login');
                return;
            }

            if (!data.session) {
                router.push('/login');
                return;
            }

            const profile = await ProfileService.getProfile(data.session.user.id);
            const isAdmin = profile?.roles?.includes('Administrador');

            if (!isAdmin) {
                router.push('/dashboard'); // Redirect unauthorized
                return;
            }

            // 2. Load Stats
            const { stats, error } = await AdminService.getSystemStats();
            if (error) {
                setError(error);
            } else {
                setStats(stats);
            }
        } catch (err) {
            console.error('Admin page error:', err);
            setError('Error de acceso');
        } finally {
            setIsLoading(false);
        }
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center min-h-[50vh]">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-slate-900"></div>
            </div>
        );
    }

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Header */}
            <div>
                <h1 className="text-3xl font-black text-slate-800 tracking-tight">Panel de Administrador</h1>
                <p className="text-slate-500 font-medium">Visi├│n general del sistema y m├®tricas clave.</p>
            </div>

            {error && (
                <div className="p-4 bg-red-50 text-red-600 rounded-xl border border-red-100 font-medium">
                    {error}
                </div>
            )}

            {/* Stats Grid */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <StatCard
                    title="Usuarios Registrados"
                    value={stats?.totalUsers || 0}
                    icon="group"
                    color="bg-blue-500"
                />
                <StatCard
                    title="Unidades Educativas"
                    value={stats?.totalUnits || 0}
                    icon="school"
                    color="bg-indigo-500"
                />
                <StatCard
                    title="PDCs Generados"
                    value={stats?.totalPDCs || 0}
                    icon="description"
                    color="bg-purple-500"
                />
            </div>

            {/* Placeholder for future sections */}
            {/* Catalog Management */}
            <div>
                <h2 className="text-xl font-bold text-slate-800 mb-4">Gesti├│n de Cat├ílogos</h2>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <Link href="/dashboard/admin/units" className="bg-white rounded-2xl p-6 border border-slate-100 shadow-sm hover:shadow-md hover:border-blue-200 transition-all group">
                        <div className="size-12 rounded-xl bg-blue-50 text-blue-600 flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                            <span className="material-symbols-rounded text-2xl">school</span>
                        </div>
                        <h3 className="font-bold text-slate-800 mb-1 group-hover:text-blue-600 transition-colors">Unidades Educativas</h3>
                        <p className="text-sm text-slate-500">Gestionar escuelas, c├│digos SIE y distritos.</p>
                    </Link>

                    <Link href="/dashboard/admin/users" className="bg-white rounded-2xl p-6 border border-slate-100 shadow-sm hover:shadow-md hover:border-purple-200 transition-all group">
                        <div className="size-12 rounded-xl bg-purple-50 text-purple-600 flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                            <span className="material-symbols-rounded text-2xl">lock_person</span>
                        </div>
                        <h3 className="font-bold text-slate-800 mb-1 group-hover:text-purple-600 transition-colors">Roles y Permisos</h3>
                        <p className="text-sm text-slate-500">Administrar usuarios y asignar roles.</p>
                    </Link>
                </div>
            </div>
        </div>
    );
}

function StatCard({ title, value, icon, color }: { title: string, value: number, icon: string, color: string }) {
    return (
        <div className="bg-white rounded-2xl p-6 border border-slate-100 shadow-xl shadow-slate-200/50 flex items-center gap-5 hover:scale-[1.02] transition-transform">
            <div className={`size-14 rounded-xl ${color} text-white flex items-center justify-center shadow-lg shadow-${color}/30`}>
                <span className="material-symbols-rounded text-2xl">{icon}</span>
            </div>
            <div>
                <p className="text-slate-500 font-bold text-xs uppercase tracking-wider">{title}</p>
                <p className="text-3xl font-black text-slate-900">{value}</p>
            </div>
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { AdminService } from '@/services/admin.service';

interface Unit {
    id: number; // ID es el SIE
    nombre: string;
    direccion: string;
    telefono: string;
    distrito_id: number;
    distrito?: {
        nombre: string;
        departamento?: { nombre: string }
    };
}

interface District {
    id: number;
    nombre: string;
    departamento?: {
        nombre: string
    };
}

export default function AdminUnitsPage() {
    const router = useRouter();
    const [units, setUnits] = useState<Unit[]>([]);
    const [districts, setDistricts] = useState<District[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');

    // Form State
    const [isEditing, setIsEditing] = useState(false);
    const [currentUnit, setCurrentUnit] = useState<Partial<Unit>>({});
    const [showModal, setShowModal] = useState(false);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        const [unitsRes, districtsRes] = await Promise.all([
            AdminService.getUnits(),
            AdminService.getDistricts()
        ]);

        if (unitsRes.data) setUnits(unitsRes.data);
        if (districtsRes.data) setDistricts(districtsRes.data);
        setLoading(false);
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setSaving(true);
        try {
            if (isEditing && currentUnit.id) {
                await AdminService.updateUnit(currentUnit.id, currentUnit as any);
            } else {
                await AdminService.createUnit(currentUnit as any);
            }
            setShowModal(false);
            loadData();
        } catch (error) {
            console.error('Error saving unit:', error);
            alert('Error al guardar. Revisa la consola.');
        } finally {
            setSaving(false);
        }
    };

    const handleDelete = async (id: number) => {
        if (!confirm('┬┐Est├ís seguro de eliminar esta unidad? Esta acci├│n no se puede deshacer.')) return;
        await AdminService.deleteUnit(id);
        loadData();
    };

    const openNew = () => {
        setCurrentUnit({});
        setIsEditing(false);
        setShowModal(true);
    };

    const openEdit = (unit: Unit) => {
        setCurrentUnit(unit);
        setIsEditing(true);
        setShowModal(true);
    };

    const filteredUnits = units.filter(u =>
        u.nombre.toLowerCase().includes(searchTerm.toLowerCase()) ||
        u.id?.toString().includes(searchTerm)
    );

    return (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <div className="flex items-center gap-2 mb-1">
                        <button onClick={() => router.back()} className="p-1 hover:bg-slate-100 rounded-full transition-colors">
                            <span className="material-symbols-rounded text-slate-500">arrow_back</span>
                        </button>
                        <h1 className="text-2xl font-black text-slate-800 tracking-tight">Unidades Educativas</h1>
                    </div>
                    <p className="text-slate-500 font-medium ml-9">Gestiona el cat├ílogo de escuelas.</p>
                </div>
                <div className="flex items-center gap-3">
                    <div className="relative">
                        <span className="material-symbols-rounded absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm">search</span>
                        <input
                            type="text"
                            placeholder="Buscar..."
                            className="pl-9 pr-4 py-2 rounded-xl border border-slate-200 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all w-full md:w-64"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                    <Button onClick={openNew}>
                        <span className="material-symbols-rounded mr-2">add</span>
                        Nueva Unidad
                    </Button>
                </div>
            </div>

            {loading ? (
                <div className="text-center py-20">
                    <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-slate-900 mx-auto"></div>
                </div>
            ) : (
                <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-slate-50 border-b border-slate-100 text-xs uppercase text-slate-500 font-bold tracking-wider">
                                <th className="p-4">Nombre / C├│digo</th>
                                <th className="p-4">Ubicaci├│n</th>
                                <th className="p-4">Distrito</th>
                                <th className="p-4 text-right">Acciones</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {filteredUnits.length === 0 ? (
                                <tr>
                                    <td colSpan={4} className="p-8 text-center text-slate-500 font-medium">
                                        No se encontraron resultados
                                    </td>
                                </tr>
                            ) : (
                                filteredUnits.map((unit) => (
                                    <tr key={unit.id} className="hover:bg-slate-50/50 transition-colors group">
                                        <td className="p-4">
                                            <p className="font-bold text-slate-800">{unit.nombre}</p>
                                            <span className="text-xs font-mono text-slate-400 bg-slate-100 px-1.5 py-0.5 rounded">{unit.id}</span>
                                        </td>
                                        <td className="p-4 text-sm text-slate-600">
                                            <div className="flex items-center gap-1.5">
                                                <span className="material-symbols-rounded text-slate-400 text-base">location_on</span>
                                                {unit.direccion || 'Sin direcci├│n'}
                                            </div>
                                        </td>
                                        <td className="p-4 text-sm text-slate-600">
                                            <div className="flex flex-col">
                                                <span className="font-medium text-slate-700">{unit.distrito?.nombre || '-'}</span>
                                                <span className="text-xs text-slate-400">{unit.distrito?.departamento?.nombre}</span>
                                            </div>
                                        </td>
                                        <td className="p-4 text-right">
                                            <div className="flex items-center justify-end gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                                <button
                                                    onClick={() => openEdit(unit)}
                                                    className="p-1.5 hover:bg-blue-50 text-slate-400 hover:text-blue-600 rounded-lg transition-colors"
                                                    title="Editar"
                                                >
                                                    <span className="material-symbols-rounded text-lg">edit</span>
                                                </button>
                                                <button
                                                    onClick={() => handleDelete(unit.id)}
                                                    className="p-1.5 hover:bg-red-50 text-slate-400 hover:text-red-600 rounded-lg transition-colors"
                                                    title="Eliminar"
                                                >
                                                    <span className="material-symbols-rounded text-lg">delete</span>
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            )}

            {/* Modal Manual (Quick Implementation) */}
            {showModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
                    <div className="bg-white rounded-2xl shadow-xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-200">
                        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                            <h3 className="text-lg font-bold text-slate-800">
                                {isEditing ? 'Editar Unidad' : 'Nueva Unidad'}
                            </h3>
                            <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600">
                                <span className="material-symbols-rounded">close</span>
                            </button>
                        </div>
                        <form onSubmit={handleSave} className="p-6 space-y-4">
                            <Input
                                label="Nombre de la Unidad"
                                value={currentUnit.nombre || ''}
                                onChange={e => setCurrentUnit({ ...currentUnit, nombre: e.target.value })}
                                required
                            />

                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-1">
                                    <label className="text-sm font-bold text-slate-700 ml-1">C├│digo SIE</label>
                                    <input
                                        type="number"
                                        className="w-full rounded-xl border border-slate-200 bg-slate-50 p-2.5 text-sm outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all"
                                        value={currentUnit.id || ''}
                                        onChange={e => setCurrentUnit({ ...currentUnit, id: parseInt(e.target.value) || undefined })}
                                        required={!isEditing}
                                        disabled={isEditing}
                                    />
                                </div>
                                <Input
                                    label="Tel├®fono"
                                    value={currentUnit.telefono || ''}
                                    onChange={e => setCurrentUnit({ ...currentUnit, telefono: e.target.value })}
                                />
                            </div>

                            <Input
                                label="Direcci├│n"
                                value={currentUnit.direccion || ''}
                                onChange={e => setCurrentUnit({ ...currentUnit, direccion: e.target.value })}
                            />

                            <div className="space-y-1">
                                <label className="text-sm font-bold text-slate-700 ml-1">Distrito</label>
                                <select
                                    className="w-full rounded-xl border-slate-200 bg-slate-50 p-2.5 text-sm outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all"
                                    value={currentUnit.distrito_id || ''}
                                    onChange={e => setCurrentUnit({ ...currentUnit, distrito_id: parseInt(e.target.value) })}
                                    required
                                >
                                    <option value="">Selecciona un distrito...</option>
                                    {districts.map(d => (
                                        <option key={d.id} value={d.id}>
                                            {d.nombre} ({d.departamento?.nombre || 'General'})
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div className="pt-4 flex justify-end gap-3">
                                <button
                                    type="button"
                                    onClick={() => setShowModal(false)}
                                    className="px-4 py-2 text-sm font-bold text-slate-500 hover:bg-slate-100 rounded-xl transition-colors"
                                >
                                    Cancelar
                                </button>
                                <Button type="submit" isLoading={saving}>
                                    Guardar
                                </Button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { AdminService } from '@/services/admin.service';

interface User {
    id: string;
    nombres: string;
    apellidos: string;
    email: string;
    roles: string[];
    created_at: string;
}

export default function AdminUsersPage() {
    const router = useRouter();
    const [users, setUsers] = useState<User[]>([]);
    const [allRoles, setAllRoles] = useState<string[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');

    // Edit Roles State
    const [currentUser, setCurrentUser] = useState<User | null>(null);
    const [selectedRoles, setSelectedRoles] = useState<string[]>([]);
    const [showModal, setShowModal] = useState(false);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        const [usersRes, rolesRes] = await Promise.all([
            AdminService.getUsers(),
            AdminService.getRoles()
        ]);

        if (usersRes.data) setUsers(usersRes.data);
        if (rolesRes.data) setAllRoles(rolesRes.data);
        setLoading(false);
    };

    const openEditRoles = (user: User) => {
        setCurrentUser(user);
        setSelectedRoles([...user.roles]);
        setShowModal(true);
    };

    const toggleRole = (role: string) => {
        if (selectedRoles.includes(role)) {
            setSelectedRoles(selectedRoles.filter(r => r !== role));
        } else {
            setSelectedRoles([...selectedRoles, role]);
        }
    };

    const handleSaveRoles = async () => {
        if (!currentUser) return;
        setSaving(true);
        try {
            await AdminService.updateUserRoles(currentUser.id, selectedRoles);
            setShowModal(false);
            loadData();
        } catch (error) {
            console.error('Error saving roles:', error);
            alert('Error al guardar roles');
        } finally {
            setSaving(false);
        }
    };

    const filteredUsers = users.filter(u =>
        (u.nombres?.toLowerCase() || '').includes(searchTerm.toLowerCase()) ||
        (u.apellidos?.toLowerCase() || '').includes(searchTerm.toLowerCase()) ||
        (u.email?.toLowerCase() || '').includes(searchTerm.toLowerCase())
    );

    return (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <div className="flex items-center gap-2 mb-1">
                        <button onClick={() => router.back()} className="p-1 hover:bg-slate-100 rounded-full transition-colors">
                            <span className="material-symbols-rounded text-slate-500">arrow_back</span>
                        </button>
                        <h1 className="text-2xl font-black text-slate-800 tracking-tight">Gesti├│n de Usuarios</h1>
                    </div>
                    <p className="text-slate-500 font-medium ml-9">Administra accesos y permisos del sistema.</p>
                </div>
                <div className="flex items-center gap-3">
                    <div className="relative">
                        <span className="material-symbols-rounded absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm">search</span>
                        <input
                            type="text"
                            placeholder="Buscar por nombre o email..."
                            className="pl-9 pr-4 py-2 rounded-xl border border-slate-200 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all w-full md:w-80"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                </div>
            </div>

            {loading ? (
                <div className="text-center py-20">
                    <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-slate-900 mx-auto"></div>
                </div>
            ) : (
                <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-slate-50 border-b border-slate-100 text-xs uppercase text-slate-500 font-bold tracking-wider">
                                <th className="p-4">Usuario</th>
                                <th className="p-4">Email</th>
                                <th className="p-4">Roles</th>
                                <th className="p-4 text-right">Acciones</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {filteredUsers.length === 0 ? (
                                <tr>
                                    <td colSpan={4} className="p-8 text-center text-slate-500 font-medium">
                                        No se encontraron usuarios
                                    </td>
                                </tr>
                            ) : (
                                filteredUsers.map((user) => (
                                    <tr key={user.id} className="hover:bg-slate-50/50 transition-colors group">
                                        <td className="p-4">
                                            <div className="flex items-center gap-3">
                                                <div className="size-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 font-bold text-xs">
                                                    {user.nombres?.[0]}{user.apellidos?.[0]}
                                                </div>
                                                <div>
                                                    <p className="font-bold text-slate-800 text-sm">{user.nombres} {user.apellidos}</p>
                                                    <p className="text-xs text-slate-400">Registrado el {new Date(user.created_at).toLocaleDateString()}</p>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="p-4 text-sm text-slate-600 font-mono">
                                            {user.email}
                                        </td>
                                        <td className="p-4">
                                            <div className="flex flex-wrap gap-1">
                                                {user.roles && user.roles.length > 0 ? (
                                                    user.roles.map(role => (
                                                        <span key={role} className={`text-xs px-2 py-0.5 rounded-full font-bold border ${role === 'Administrador'
                                                                ? 'bg-purple-100 text-purple-700 border-purple-200'
                                                                : 'bg-blue-50 text-blue-600 border-blue-100'
                                                            }`}>
                                                            {role}
                                                        </span>
                                                    ))
                                                ) : (
                                                    <span className="text-xs text-slate-400 italic">Sin roles</span>
                                                )}
                                            </div>
                                        </td>
                                        <td className="p-4 text-right">
                                            <Button
                                                variant="outline"
                                                size="sm"
                                                onClick={() => openEditRoles(user)}
                                                className="opacity-0 group-hover:opacity-100 transition-opacity"
                                            >
                                                <span className="material-symbols-rounded text-base mr-1">shield_person</span>
                                                Roles
                                            </Button>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            )}

            {/* Modal Edit Roles */}
            {showModal && currentUser && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
                    <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden animate-in zoom-in-95 duration-200">
                        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                            <h3 className="text-lg font-bold text-slate-800">
                                Gestionar Roles
                            </h3>
                            <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600">
                                <span className="material-symbols-rounded">close</span>
                            </button>
                        </div>
                        <div className="p-6">
                            <p className="text-sm text-slate-500 mb-4">
                                Asignando roles para <span className="font-bold text-slate-800">{currentUser.nombres} {currentUser.apellidos}</span>
                            </p>

                            <div className="space-y-2">
                                {allRoles.map(role => {
                                    const isSelected = selectedRoles.includes(role);
                                    return (
                                        <div
                                            key={role}
                                            onClick={() => toggleRole(role)}
                                            className={`flex items-center justify-between p-3 rounded-xl border cursor-pointer transition-all ${isSelected
                                                    ? 'bg-blue-50 border-blue-200 shadow-sm'
                                                    : 'bg-white border-slate-200 hover:border-blue-200 hover:bg-slate-50'
                                                }`}
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className={`size-5 rounded border flex items-center justify-center ${isSelected ? 'bg-blue-500 border-blue-500' : 'border-slate-300'
                                                    }`}>
                                                    {isSelected && <span className="material-symbols-rounded text-white text-sm font-bold">check</span>}
                                                </div>
                                                <span className={`font-medium ${isSelected ? 'text-blue-700' : 'text-slate-700'}`}>{role}</span>
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>

                            <div className="pt-6 flex justify-end gap-3">
                                <button
                                    onClick={() => setShowModal(false)}
                                    className="px-4 py-2 text-sm font-bold text-slate-500 hover:bg-slate-100 rounded-xl transition-colors"
                                >
                                    Cancelar
                                </button>
                                <Button onClick={handleSaveRoles} isLoading={saving}>
                                    Guardar Cambios
                                </Button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import { useEffect, useState, use, useRef } from 'react';
import { useRouter } from 'next/navigation';
import { AreasService, AreaTrabajo } from '@/services/areas.service';
import { LibraryService, ContentItem, UserContent } from '@/services/library.service';
import { Button } from '@/components/ui/button';

export default function AreaDashboardPage({ params }: { params: Promise<{ id: string }> }) {
    const { id } = use(params);
    const router = useRouter();
    const editRef = useRef<HTMLDivElement>(null);
    const [area, setArea] = useState<AreaTrabajo | null>(null);
    const [baseContents, setBaseContents] = useState<ContentItem[]>([]);
    const [userContents, setUserContents] = useState<UserContent[]>([]);
    const [loading, setLoading] = useState(true);
    const [copyingId, setCopyingId] = useState<number | null>(null);
    const [isCopyingAll, setIsCopyingAll] = useState(false);
    const [expandedThemes, setExpandedThemes] = useState<Set<number>>(new Set());
    const [expandedUserThemes, setExpandedUserThemes] = useState<Set<number>>(new Set());
    const [editingContentId, setEditingContentId] = useState<number | null>(null);
    const [editingTitle, setEditingTitle] = useState('');
    const [isAddingNew, setIsAddingNew] = useState(false);
    const [newTitle, setNewTitle] = useState('');
    const [isSavedRecently, setIsSavedRecently] = useState(false);

    useEffect(() => {
        loadData();
    }, [id]);

    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            const target = event.target as HTMLElement;
            // Si el clic no es dentro de un contenedor de edici├│n, cerramos los editores
            if (!target.closest('.editor-container')) {
                setEditingContentId(null);
                setIsAddingNew(false);
            }
        }
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const loadData = async () => {
        setLoading(true);
        const areaData = await AreasService.getAreaById(id);
        if (areaData) {
            setArea(areaData);
            const [baseData, userData] = await Promise.all([
                LibraryService.getBaseContentsByArea(areaData.area_conocimiento.id),
                LibraryService.getUserContents(id)
            ]);
            setBaseContents(baseData);
            setUserContents(userData);
        }
        setLoading(false);
    };

    const handleCopy = async (baseId: number) => {
        setCopyingId(baseId);
        const result = await LibraryService.copyContentToUser(baseId, id);
        if (result.success) {
            const userData = await LibraryService.getUserContents(id);
            setUserContents(userData);
        } else {
            alert('Error al copiar contenido');
        }
        setCopyingId(null);
    };

    const handleCopyAll = async () => {
        // Warning if there are existing contents
        if (userContents.length > 0) {
            const confirmed = confirm(
                `Atenci├│n: Ya tienes ${userContents.length} contenidos en tu lista. \n\n` +
                'Si contin├║as, SE BORRAR├üN todos tus contenidos actuales de esta ├írea y se reemplazar├ín por los oficiales del curr├¡culo base. \n\n' +
                '┬┐Est├ís seguro de que deseas REEMPLAZAR todo?'
            );
            if (!confirmed) return;

            setIsCopyingAll(true);
            // Clear existing contents first
            const clearResult = await LibraryService.clearUserContents(id);
            if (!clearResult) {
                alert('Error al limpiar los contenidos previos.');
                setIsCopyingAll(false);
                return;
            }
        } else {
            if (!confirm('┬┐Deseas copiar todos los contenidos base oficiales a tu lista de contenidos editables?')) return;
            setIsCopyingAll(true);
        }

        const result = await LibraryService.copyAllBaseContentsToUser(area!.area_conocimiento.id, id);
        if (result.success) {
            const userData = await LibraryService.getUserContents(id);
            setUserContents(userData);
        } else {
            alert('Error al copiar contenidos base');
        }
        setIsCopyingAll(false);
    };

    const [isSaving, setIsSaving] = useState<number | 'new' | null>(null);
    const [error, setError] = useState<string | null>(null);

    const handleUpdate = async (contentId: number, shouldClose = true) => {
        if (!editingTitle.trim()) return;
        if (isSaving === contentId) return;

        setIsSaving(contentId);
        setError(null);
        try {
            const result = await LibraryService.updateUserContent(contentId, {
                titulo: editingTitle
            });

            if (result.success) {
                setUserContents(prev => prev.map(c => c.id === contentId ? {
                    ...c,
                    titulo: editingTitle,
                    updated_at: new Date().toISOString()
                } : c));

                if (shouldClose) {
                    setEditingContentId(null);
                    setEditingTitle('');
                }
            } else {
                console.error('Update failed:', result.error);
                setError(result.error?.message || 'Error al guardar cambios. Verifica el ID o permisos.');
                // No cerramos el editor si falla, para que el usuario no pierda lo que escribi├│
            }
        } catch (error) {
            console.error('Failed to update content:', error);
            setError('Error de conexi├│n al intentar guardar.');
        } finally {
            setIsSaving(null);
        }
    };

    const handleCreateTheme = async (titulo: string, shouldClose = true) => {
        if (!titulo.trim()) {
            if (shouldClose) setIsAddingNew(false);
            return false;
        }

        setIsSaving('new');
        setError(null);
        try {
            const result = await LibraryService.createCustomContent(id, titulo);
            if (result.success) {
                const userData = await LibraryService.getUserContents(id);
                setUserContents(userData);
                if (shouldClose) {
                    setIsAddingNew(false);
                    setNewTitle('');
                }
                return true;
            } else {
                setError(result.error?.message || 'Error al crear el tema.');
            }
        } catch (error) {
            console.error('Failed to create theme:', error);
            setError('Error de conexi├│n al crear tema.');
        } finally {
            setIsSaving(null);
        }
        return false;
    };

    useEffect(() => {
        if (!editingContentId) {
            setEditingTitle('');
        }
    }, [editingContentId]);

    const handleCreateSubtheme = async (padreId: number) => {
        const titulo = prompt('T├¡tulo del subtema:');
        if (!titulo) return;

        setError(null);
        const result = await LibraryService.createCustomSubtheme(id, padreId, titulo);
        if (result.success) {
            const userData = await LibraryService.getUserContents(id);
            setUserContents(userData);
            const nextExpanded = new Set(expandedUserThemes);
            nextExpanded.add(padreId);
            setExpandedUserThemes(nextExpanded);
        } else {
            setError(result.error?.message || 'Error al crear subtema.');
        }
    };

    const handleReorder = async (content: UserContent, direction: 'up' | 'down') => {
        const siblings = userContents
            .filter(c => c.padre_id === content.padre_id)
            .sort((a, b) => a.orden - b.orden);

        const currentIndex = siblings.findIndex(s => s.id === content.id);
        const targetIndex = direction === 'up' ? currentIndex - 1 : currentIndex + 1;

        if (targetIndex >= 0 && targetIndex < siblings.length) {
            const target = siblings[targetIndex];
            const success = await LibraryService.reorderUserContent(content.id, content.orden, target.id, target.orden);
            if (success) {
                const userData = await LibraryService.getUserContents(id);
                setUserContents(userData);
            }
        }
    };

    const handleDelete = async (contentId: number) => {
        if (!confirm('┬┐Est├ís seguro de eliminar este contenido personalizado?')) return;
        const success = await LibraryService.deleteUserContent(contentId);
        if (success) {
            setUserContents(userContents.filter(c => c.id !== contentId));
        }
    };

    const toggleTheme = (themeId: number) => {
        const next = new Set(expandedThemes);
        if (next.has(themeId)) next.delete(themeId);
        else next.add(themeId);
        setExpandedThemes(next);
    };

    const toggleUserTheme = (themeId: number) => {
        const next = new Set(expandedUserThemes);
        if (next.has(themeId)) next.delete(themeId);
        else next.add(themeId);
        setExpandedUserThemes(next);
    };

    // Organize hierarchy
    const themes = baseContents.filter(c => !c.padre_id);
    const getSubthemes = (parentId: number) => baseContents.filter(c => c.padre_id === parentId);

    if (loading) {
        return (
            <div className="p-8">
                <div className="animate-pulse space-y-4">
                    <div className="h-8 w-64 bg-slate-200 rounded"></div>
                    <div className="h-4 w-48 bg-slate-100 rounded"></div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-12">
                        {[1, 2, 3, 4].map(i => (
                            <div key={i} className="h-40 bg-slate-50 rounded-2xl border border-slate-100"></div>
                        ))}
                    </div>
                </div>
            </div>
        );
    }

    if (!area) {
        return (
            <div className="p-12 text-center">
                <h2 className="text-xl font-bold text-slate-800">├ürea de trabajo no encontrada</h2>
                <Button variant="ghost" onClick={() => router.push('/dashboard/areas')} className="mt-4">
                    Volver a mis ├íreas
                </Button>
            </div>
        );
    }

    return (
        <div className="space-y-8 animate-in fade-in duration-700">
            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div className="space-y-1">
                    <div className="flex items-center gap-2 mb-2">
                        <button onClick={() => router.back()} className="p-1.5 hover:bg-slate-100 rounded-full transition-colors">
                            <span className="material-symbols-rounded text-slate-500">arrow_back</span>
                        </button>
                        <span className="text-xs font-black text-blue-600 bg-blue-50 px-2.5 py-1 rounded-lg uppercase tracking-wider">
                            {area.unidad_educativa.nombre}
                        </span>
                    </div>
                    <h1 className="text-3xl font-black text-slate-900 tracking-tight ml-1">
                        {area.area_conocimiento.nombre}
                    </h1>
                    <div className="flex items-center gap-2 text-slate-500 font-medium text-sm ml-1">
                        <span className="material-symbols-rounded text-base text-slate-400">school</span>
                        <span>{(area.area_conocimiento as any).grado?.nombre} ÔÇó {(area.area_conocimiento as any).grado?.nivel?.nombre}</span>
                        <span className="mx-1 opacity-30">|</span>
                        <span className="material-symbols-rounded text-base text-slate-400">schedule</span>
                        <span>{area.turno.nombre}</span>
                        <span className="mx-1 opacity-30">|</span>
                        <span className="material-symbols-rounded text-base text-slate-400">group</span>
                        <div className="flex gap-1">
                            {area.paralelos.map(p => (
                                <span key={p.id} className="bg-slate-100 px-1.5 rounded text-slate-800 font-bold">
                                    {p.nombre}
                                </span>
                            ))}
                        </div>
                    </div>
                </div>

                <div className="flex gap-3">
                    <Button
                        variant="outline"
                        className="w-auto px-6 h-11 border-slate-200 cursor-default"
                        onClick={(e) => e.stopPropagation()}
                    >
                        <span className="material-symbols-rounded text-base mr-2">settings</span>
                        Configurar
                    </Button>
                    <Button
                        className="w-auto px-8 h-11 bg-blue-600 shadow-blue-500/20 cursor-default"
                        onClick={(e) => e.stopPropagation()}
                    >
                        <span className="material-symbols-rounded text-base mr-2">auto_awesome</span>
                        Planificar con IA
                    </Button>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-[1fr_auto_1fr] gap-8 items-start">
                {/* Contenidos Base Accordion */}
                <div className="space-y-6">
                    <div className="flex items-center justify-between border-b border-slate-100 pb-4">
                        <h2 className="text-xl font-black text-slate-800 flex items-center gap-2">
                            <span className="material-symbols-rounded text-blue-500">verified</span>
                            Contenidos Base Oficiales
                        </h2>
                    </div>

                    <Button
                        onClick={handleCopyAll}
                        disabled={isCopyingAll || themes.length === 0}
                        className="lg:hidden w-full h-12 bg-white border border-slate-200 text-blue-600 rounded-2xl flex items-center justify-center gap-2 hover:bg-slate-50 transition-all font-black text-sm"
                    >
                        {isCopyingAll ? (
                            <div className="w-5 h-5 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                        ) : (
                            <>
                                <span className="material-symbols-rounded">double_arrow</span>
                                COPIAR TODO AL PLANIFICADOR
                            </>
                        )}
                    </Button>

                    <div className="space-y-3">
                        {themes.map(theme => {
                            const isExpanded = expandedThemes.has(theme.id);
                            const subthemes = getSubthemes(theme.id);

                            return (
                                <div key={theme.id} className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden transition-all hover:border-blue-100">
                                    <div
                                        onClick={() => toggleTheme(theme.id)}
                                        className="p-5 flex items-center justify-between cursor-pointer hover:bg-slate-50 transition-colors"
                                    >
                                        <div className="flex items-center gap-4">
                                            <div className={`w-8 h-8 rounded-full flex items-center justify-center transition-all ${isExpanded ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-400'}`}>
                                                <span className="text-xs font-black">{theme.orden}</span>
                                            </div>
                                            <h3 className="font-bold text-slate-900">{theme.titulo}</h3>
                                        </div>
                                        <span className={`material-symbols-rounded transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`}>
                                            expand_more
                                        </span>
                                    </div>

                                    {isExpanded && (
                                        <div className="px-5 pb-5 pt-1 space-y-2 border-t border-slate-50 bg-slate-50/30">
                                            {subthemes.length > 0 ? subthemes.map(sub => (
                                                <div key={sub.id} className="bg-white p-4 rounded-2xl border border-slate-100 flex items-center justify-between group">
                                                    <div className="flex items-center gap-3">
                                                        <span className="text-[10px] font-black text-slate-300 w-5">{theme.orden}.{sub.orden}</span>
                                                        <span className="text-sm font-medium text-slate-700">{sub.titulo}</span>
                                                    </div>
                                                    <button
                                                        onClick={() => handleCopy(sub.id)}
                                                        disabled={copyingId === sub.id}
                                                        className="p-2 text-blue-600 hover:bg-blue-50 rounded-xl transition-all opacity-0 group-hover:opacity-100 disabled:opacity-50"
                                                        title="Copiar a mis contenidos"
                                                    >
                                                        {copyingId === sub.id ? (
                                                            <div className="w-5 h-5 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                                                        ) : (
                                                            <span className="material-symbols-rounded text-xl">content_copy</span>
                                                        )}
                                                    </button>
                                                </div>
                                            )) : (
                                                <div className="flex justify-between items-center bg-white p-4 rounded-2xl border border-slate-100">
                                                    <span className="text-sm text-slate-400 italic">No hay subtemas definidos.</span>
                                                    <button
                                                        onClick={() => handleCopy(theme.id)}
                                                        className="p-2 text-blue-600 hover:bg-blue-50 rounded-xl transition-all"
                                                        title="Copiar este tema"
                                                    >
                                                        <span className="material-symbols-rounded text-xl">content_copy</span>
                                                    </button>
                                                </div>
                                            )}
                                        </div>
                                    )}
                                </div>
                            );
                        })}

                        {themes.length === 0 && (
                            <div className="py-12 text-center bg-slate-50 rounded-[2.5rem] border-2 border-dashed border-slate-200">
                                <span className="material-symbols-rounded text-4xl text-slate-200 mb-3 block">sentiment_dissatisfied</span>
                                <p className="text-slate-400 font-medium">No se encontraron contenidos para esta ├írea.</p>
                            </div>
                        )}
                    </div>
                </div>

                {/* Middle Action */}
                <div className="hidden lg:flex flex-col items-center justify-center pt-24 sticky top-10">
                    <div className="w-px h-20 bg-gradient-to-b from-transparent via-slate-200 to-transparent"></div>
                    <button
                        onClick={handleCopyAll}
                        disabled={isCopyingAll || themes.length === 0}
                        className="my-6 w-12 h-12 rounded-full bg-white border border-slate-200 shadow-xl shadow-blue-500/10 flex items-center justify-center text-blue-600 hover:scale-110 hover:border-blue-500 transition-all group disabled:opacity-50 disabled:scale-100"
                        title="Copiar todos los contenidos oficiales"
                    >
                        {isCopyingAll ? (
                            <div className="w-5 h-5 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                        ) : (
                            <span className="material-symbols-rounded text-2xl group-hover:rotate-180 transition-transform duration-500">double_arrow</span>
                        )}
                    </button>
                    <div className="w-px h-20 bg-gradient-to-b from-transparent via-slate-200 to-transparent"></div>
                </div>

                {/* Mis Contenidos Section */}
                <div className="space-y-6">
                    <div className="flex items-center justify-between border-b border-slate-100 pb-4">
                        <h2 className="text-xl font-black text-slate-800 flex items-center gap-2">
                            <span className="material-symbols-rounded text-blue-500">edit_note</span>
                            Mis Contenidos Editables
                        </h2>
                        <div className="flex items-center gap-3">
                            <span className="px-3 py-1 bg-slate-50 text-slate-500 rounded-full text-[10px] font-black uppercase tracking-widest border border-slate-100">
                                {userContents.length} PERSONALIZADOS
                            </span>
                            <button
                                onClick={() => {
                                    setIsAddingNew(true);
                                    setNewTitle('');
                                    setEditingContentId(null);
                                }}
                                className="w-8 h-8 rounded-full bg-blue-600 text-white flex items-center justify-center hover:bg-blue-700 transition-all shadow-lg shadow-blue-500/20"
                                title="Nuevo Tema"
                            >
                                <span className="material-symbols-rounded text-base">add</span>
                            </button>
                        </div>
                    </div>

                    <div className="space-y-4">
                        {isAddingNew && (
                            <div className="editor-container bg-white rounded-3xl border-2 border-dashed border-blue-200 p-5 animate-in zoom-in-95 duration-200">
                                <div className="space-y-3">
                                    <div className="flex items-center justify-between">
                                        <h4 className="text-xs font-black text-blue-600 uppercase tracking-widest">Nuevo Tema / Contenido</h4>
                                        <button
                                            onClick={() => setIsAddingNew(false)}
                                            className="text-slate-300 hover:text-slate-500 transition-colors"
                                        >
                                            <span className="material-symbols-rounded text-base">close</span>
                                        </button>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <input
                                            autoFocus
                                            className="grow bg-slate-50 border-b-2 border-blue-500 px-3 py-2 rounded-t-xl font-bold text-slate-900 focus:outline-none transition-all"
                                            value={newTitle}
                                            placeholder="Escribe el t├¡tulo aqu├¡..."
                                            onChange={(e) => setNewTitle(e.target.value)}
                                            onKeyDown={(e) => {
                                                if (e.key === 'Enter') handleCreateTheme(newTitle);
                                                if (e.key === 'Escape') setIsAddingNew(false);
                                            }}
                                            onBlur={() => {
                                                if (newTitle.trim()) handleCreateTheme(newTitle, false);
                                                else setIsAddingNew(false);
                                            }}
                                        />
                                        {isSaving === 'new' && (
                                            <span className="material-symbols-rounded animate-spin text-blue-500 text-sm">sync</span>
                                        )}
                                        {error && isAddingNew && (
                                            <span className="material-symbols-rounded text-red-500 text-sm" title={error}>error</span>
                                        )}
                                    </div>
                                    {error && isAddingNew && (
                                        <p className="text-[10px] text-red-500 font-bold bg-red-50 p-2 rounded-xl mt-2 border border-red-100">
                                            {error}
                                        </p>
                                    )}
                                    {isSaving === 'new' && (
                                        <p className="text-[10px] text-blue-500 font-bold uppercase tracking-widest animate-pulse pl-3 italic">
                                            Guardando cambios...
                                        </p>
                                    )}
                                </div>
                            </div>
                        )}

                        {(() => {
                            const userThemes = userContents.filter(c => !c.padre_id);
                            const getUserSubthemes = (parentId: number) => userContents.filter(c => c.padre_id === parentId);
                            const orphanedSubthemes = userContents.filter(c => c.padre_id && !userThemes.find(t => t.id === c.padre_id));

                            const renderThemeAccordion = (theme: UserContent, index: number) => {
                                const subthemes = getUserSubthemes(theme.id);
                                const hasSubthemes = subthemes.length > 0;
                                const isExpanded = expandedUserThemes.has(theme.id);

                                return (
                                    <div key={theme.id} className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden transition-all hover:border-blue-100 group">
                                        {/* Theme Card / Accordion Header */}
                                        <div
                                            onClick={() => hasSubthemes && toggleUserTheme(theme.id)}
                                            className="p-5 flex items-center justify-between cursor-pointer hover:bg-slate-50 transition-colors"
                                        >
                                            <div className="flex items-center gap-4 flex-1">
                                                {/* Index Circle aligned with Base Theme */}
                                                <div className={`w-8 h-8 shrink-0 flex items-center justify-center rounded-full font-black text-xs transition-all ${isExpanded ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-400 group-hover:bg-blue-50 group-hover:text-blue-500'}`}>
                                                    {index + 1}
                                                </div>
                                                <div className="flex-1">
                                                    {renderUserContentInner(theme, false, true)}
                                                </div>
                                            </div>

                                            <div className="flex items-center gap-4">
                                                <div className="text-right flex flex-col items-end gap-0.5 opacity-0 group-hover:opacity-100 transition-all">
                                                    <div className="text-[8px] font-black text-slate-300 uppercase underline decoration-blue-500/30">ACTUALIZADO</div>
                                                    <div className="text-[10px] font-bold text-slate-400">
                                                        {new Date(theme.updated_at).toLocaleDateString()}
                                                    </div>
                                                </div>
                                                {hasSubthemes && (
                                                    <span className={`material-symbols-rounded transition-transform duration-300 text-slate-400 ${isExpanded ? 'rotate-180 text-blue-600' : ''}`}>
                                                        expand_more
                                                    </span>
                                                )}
                                            </div>
                                        </div>

                                        {/* Nested Subthemes */}
                                        {hasSubthemes && isExpanded && (
                                            <div className="px-5 pb-5 pt-1 space-y-2 border-t border-slate-50 bg-slate-50/30">
                                                {subthemes.map((sub, subIdx) => (
                                                    <div
                                                        key={sub.id}
                                                        className="bg-white p-4 rounded-2xl border border-slate-100 flex items-center justify-between group/sub"
                                                    >
                                                        <div className="flex items-center gap-3 flex-1">
                                                            <span className="text-[10px] font-black text-slate-300 w-5">{index + 1}.{subIdx + 1}</span>
                                                            <div className="flex-1">
                                                                {renderUserContentInner(sub, true)}
                                                            </div>
                                                        </div>
                                                        <div className="opacity-0 group-hover/sub:opacity-40 transition-opacity">
                                                            <span className="material-symbols-rounded text-xl text-slate-400">arrow_forward_ios</span>
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                );
                            };

                            function renderUserContentInner(content: UserContent, isPotentialSubtheme = false, isHeader = false) {
                                const isSubtheme = isPotentialSubtheme || !!content.padre_id;
                                return editingContentId === content.id ? (
                                    <div className="editor-container py-2 space-y-2 relative" onClick={(e) => e.stopPropagation()}>
                                        <div className="flex items-center gap-2">
                                            <input
                                                autoFocus
                                                className="grow bg-slate-50 border-b-2 border-blue-500 px-0 py-1 font-bold text-slate-900 focus:outline-none transition-all"
                                                value={editingTitle}
                                                placeholder="T├¡tulo..."
                                                onChange={(e) => setEditingTitle(e.target.value)}
                                                onKeyDown={(e) => {
                                                    if (e.key === 'Enter') handleUpdate(content.id, true);
                                                    if (e.key === 'Escape') setEditingContentId(null);
                                                }}
                                                onBlur={() => handleUpdate(content.id, false)}
                                            />
                                            {isSaving === content.id && (
                                                <span className="material-symbols-rounded animate-spin text-blue-500 text-xs">sync</span>
                                            )}
                                        </div>
                                        {isSaving === content.id && (
                                            <div className="absolute -bottom-1 left-0 flex items-center gap-1.5 p-1 bg-white/80 rounded-md shadow-sm border border-blue-50/50 z-10">
                                                <span className="material-symbols-rounded text-[10px] text-blue-500 animate-spin">sync</span>
                                                <span className="text-[9px] font-black text-blue-600 uppercase tracking-widest">Sincronizando...</span>
                                            </div>
                                        )}
                                        {error && editingContentId === content.id && (
                                            <div className="absolute -bottom-1 left-0 flex items-center gap-1.5 p-1 bg-red-50 rounded-md shadow-sm border border-red-100 z-10">
                                                <span className="material-symbols-rounded text-[10px] text-red-500">error</span>
                                                <span className="text-[9px] font-black text-red-600 uppercase tracking-widest leading-none">
                                                    Error: Lo sentimos, no se pudieron guardar los cambios. <br />
                                                    Aseg├║rate de haber ejecutado la migraci├│n de 'subtitulo'.
                                                </span>
                                            </div>
                                        )}
                                    </div>
                                ) : (
                                    <div className="flex items-center justify-between gap-4 group/inner">
                                        <div className="flex items-center gap-4">
                                            <div className="space-y-0.5">
                                                <h3 className={`${isSubtheme ? 'text-sm font-medium' : 'text-base font-bold'} text-slate-800 transition-colors group-hover:text-blue-700`}>
                                                    {content.titulo}
                                                </h3>
                                            </div>
                                            <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                                <span className="text-[9px] font-black text-blue-500 uppercase tracking-tighter bg-blue-50 px-2 py-0.5 rounded-md border border-blue-100/50">
                                                    {isSubtheme ? 'SUB' : 'TEMA'}
                                                </span>
                                                {content.origen_base_id && (
                                                    <span className="material-symbols-rounded text-base text-slate-300" title="Base oficial">verified</span>
                                                )}
                                            </div>
                                        </div>
                                        <div className="flex gap-1 opacity-0 group-hover/inner:opacity-100 transition-all" onClick={(e) => e.stopPropagation()}>
                                            {/* Reordering */}
                                            <div className="flex border-r border-slate-100 mr-1 pr-1">
                                                <button
                                                    onClick={() => handleReorder(content, 'up')}
                                                    className="w-7 h-7 flex items-center justify-center text-slate-300 hover:text-blue-500 hover:bg-slate-50 rounded-lg transition-all"
                                                    title="Mover arriba"
                                                >
                                                    <span className="material-symbols-rounded text-base">arrow_upward</span>
                                                </button>
                                                <button
                                                    onClick={() => handleReorder(content, 'down')}
                                                    className="w-7 h-7 flex items-center justify-center text-slate-300 hover:text-blue-500 hover:bg-slate-50 rounded-lg transition-all"
                                                    title="Mover abajo"
                                                >
                                                    <span className="material-symbols-rounded text-base">arrow_downward</span>
                                                </button>
                                            </div>

                                            {/* Actions */}
                                            {isHeader && (
                                                <button
                                                    onClick={() => handleCreateSubtheme(content.id)}
                                                    className="w-8 h-8 flex items-center justify-center text-slate-300 hover:text-green-600 hover:bg-green-50 rounded-lg transition-all"
                                                    title="A├▒adir subtema"
                                                >
                                                    <span className="material-symbols-rounded text-lg">add_box</span>
                                                </button>
                                            )}
                                            <button
                                                onClick={() => {
                                                    setEditingContentId(content.id);
                                                    setEditingTitle(content.titulo);
                                                }}
                                                className="w-8 h-8 flex items-center justify-center text-slate-300 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all"
                                                title="Editar"
                                            >
                                                <span className="material-symbols-rounded text-lg">edit</span>
                                            </button>
                                            <button
                                                onClick={() => handleDelete(content.id)}
                                                className="w-8 h-8 flex items-center justify-center text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all"
                                                title="Eliminar"
                                            >
                                                <span className="material-symbols-rounded text-lg">delete</span>
                                            </button>
                                        </div>
                                    </div>
                                );
                            }

                            return (
                                <>
                                    {userThemes.map((t, idx) => renderThemeAccordion(t, idx))}

                                    {/* Orphaned Subthemes fallback */}
                                    {orphanedSubthemes.length > 0 && (
                                        <div className="mt-12 space-y-4">
                                            <div className="px-4 py-2 bg-amber-50 rounded-xl border border-amber-100 inline-block">
                                                <span className="text-[10px] font-black text-amber-600 uppercase tracking-widest">Contenidos sin categor├¡a</span>
                                            </div>
                                            {orphanedSubthemes.map((sub, idx) => renderThemeAccordion(sub, userThemes.length + idx))}
                                        </div>
                                    )}
                                </>
                            );
                        })()}

                        {userContents.length === 0 && (
                            <div className="py-16 text-center bg-slate-50/50 rounded-[3rem] border-2 border-dashed border-slate-200">
                                <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto mb-4 border border-slate-100 shadow-sm">
                                    <span className="material-symbols-rounded text-3xl text-slate-300">add_task</span>
                                </div>
                                <h3 className="font-bold text-slate-900 mb-1">Crea tu primer contenido</h3>
                                <p className="text-slate-400 text-sm max-w-[240px] mx-auto font-medium">
                                    Copia contenidos desde el curr├¡culo base para empezar a editarlos y personalizarlos.
                                </p>
                            </div>
                        )}

                        <div className="pt-6 flex flex-col items-center gap-3 border-t border-slate-50">
                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest flex items-center gap-2">
                                <span className="material-symbols-rounded text-blue-500 text-base">sync</span>
                                Sincronizaci├│n autom├ítica activa
                            </p>
                            <p className="text-[10px] text-slate-300 font-medium uppercase tracking-widest">
                                ├Ültima actualizaci├│n: {new Date().toLocaleTimeString()}
                            </p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { AreasService, AreaTrabajo, Catalogs } from '@/services/areas.service';
import { CatalogService } from '@/services/catalog.service';
import { AuthService } from '@/services/auth.service';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';

// Simple Icons
const IconSchool = () => <span className="material-symbols-rounded">school</span>;
const IconAdd = () => <span className="material-symbols-rounded">add</span>;
const IconDelete = () => <span className="material-symbols-rounded text-red-500 hover:text-red-700">delete</span>;
const IconSchedule = () => <span className="material-symbols-rounded text-sm">schedule</span>;
const IconGroup = () => <span className="material-symbols-rounded text-sm">group</span>;

export default function WorkAreasPage() {
    const router = useRouter();
    const [areas, setAreas] = useState<AreaTrabajo[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isCreating, setIsCreating] = useState(false);
    const [showModal, setShowModal] = useState(false);
    const [editingAreaId, setEditingAreaId] = useState<string | null>(null);
    const [isSaving, setIsSaving] = useState(false);

    // Catalogs State
    const [unidades, setUnidades] = useState<{ id: number; nombre: string; }[]>([]);
    const [niveles, setNiveles] = useState<{ id: number; nombre: string; }[]>([]);
    const [grados, setGrados] = useState<{ id: number; nombre: string; }[]>([]);
    const [areasConocimiento, setAreasConocimiento] = useState<{ id: number; nombre: string; }[]>([]);
    const [turnos, setTurnos] = useState<{ id: string; nombre: string; }[]>([]);
    const [paralelos, setParalelos] = useState<{ id: string; nombre: string; }[]>([]);

    // Form State
    const [selectedNivel, setSelectedNivel] = useState<number | ''>('');
    const [selectedGrado, setSelectedGrado] = useState<number | ''>('');

    // Location State
    const [departamentos, setDepartamentos] = useState<{ id: number; nombre: string; }[]>([]);
    const [distritos, setDistritos] = useState<{ id: number; nombre: string; }[]>([]);
    const [selectedDepto, setSelectedDepto] = useState<number | ''>('');
    const [selectedDistrito, setSelectedDistrito] = useState<number | ''>('');

    const [formData, setFormData] = useState({
        unidad_educativa_id: '' as number | '',
        area_conocimiento_id: '' as number | '',
        turno_id: '',
        paralelos_ids: [] as string[]
    });

    // Initial Load
    useEffect(() => {
        loadInitialData();
    }, []);

    // Load Grades when Nivel changes
    useEffect(() => {
        if (selectedNivel) {
            CatalogService.getGrados(selectedNivel).then(setGrados);
        } else {
            setGrados([]);
            setSelectedGrado('');
            setAreasConocimiento([]);
        }
    }, [selectedNivel]);

    // Load Areas when Grade changes
    useEffect(() => {
        if (selectedGrado) {
            CatalogService.getAreasByGrado(selectedGrado).then(setAreasConocimiento);
        } else {
            setAreasConocimiento([]);
            setFormData(prev => ({ ...prev, area_conocimiento_id: '' }));
        }
    }, [selectedGrado]);

    // Load Districts when Depto changes
    useEffect(() => {
        if (selectedDepto) {
            CatalogService.getDistritos(selectedDepto).then(setDistritos);
        } else {
            setDistritos([]);
            setSelectedDistrito('');
            setUnidades([]);
        }
    }, [selectedDepto]);

    // Load Units when Distrito changes
    useEffect(() => {
        if (selectedDistrito) {
            CatalogService.getUnidades(selectedDistrito).then(setUnidades);
        } else {
            setUnidades([]);
            setFormData(prev => ({ ...prev, unidad_educativa_id: '' }));
        }
    }, [selectedDistrito]);

    const loadInitialData = async () => {
        try {
            const { data: { session } } = await AuthService.getSession();
            if (session?.user) {
                const [areasData, deptosData, n, t, p] = await Promise.all([
                    AreasService.getAreas(session.user.id),
                    CatalogService.getDepartamentos(),
                    CatalogService.getNiveles(),
                    CatalogService.getTurnos(),
                    CatalogService.getParalelos()
                ]);

                setAreas(areasData);
                setDepartamentos(deptosData);
                setNiveles(n);
                setTurnos(t);
                setParalelos(p);
                // Units are loaded dynamically now

            }
        } catch (error) {
            console.error('Error loading data:', error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleSave = async () => {
        setIsSaving(true);
        try {
            const { data: { session } } = await AuthService.getSession();
            if (!session?.user) return;

            let result;
            if (editingAreaId) {
                result = await AreasService.updateArea(editingAreaId, {
                    unidad_educativa_id: formData.unidad_educativa_id as number,
                    area_conocimiento_id: formData.area_conocimiento_id as number,
                    turno_id: formData.turno_id,
                    paralelos_ids: formData.paralelos_ids
                });
            } else {
                result = await AreasService.createArea({
                    profesor_id: session.user.id,
                    unidad_educativa_id: formData.unidad_educativa_id as number,
                    area_conocimiento_id: formData.area_conocimiento_id as number,
                    turno_id: formData.turno_id,
                    paralelos_ids: formData.paralelos_ids
                });
            }

            if (result.success) {
                setShowModal(false);
                resetForm();
                loadInitialData(); // Reload areas
            } else {
                alert(`Error al ${editingAreaId ? 'actualizar' : 'crear'} ├írea de trabajo`);
            }
        } catch (error) {
            console.error(error);
        } finally {
            setIsSaving(false);
        }
    };

    const resetForm = () => {
        setFormData({
            unidad_educativa_id: '',
            area_conocimiento_id: '',
            turno_id: '',
            paralelos_ids: []
        });
        setSelectedNivel('');
        setSelectedGrado('');
        setSelectedDepto('');
        setSelectedDistrito('');
        setEditingAreaId(null);
    };

    const handleEdit = async (area: AreaTrabajo) => {
        setIsLoading(true);
        try {
            // Fetch full details to get depto/distrito IDs
            const fullArea = await AreasService.getAreaById(area.id);
            if (!fullArea) return;

            // Load dependent catalogs in parallel BEFORE setting values to avoid race conditions
            const ue = fullArea.unidad_educativa as any;
            const dist = ue.distrito;
            const depto = dist.departamento;
            const ac = fullArea.area_conocimiento as any;
            const grado = ac.grado;
            const nivel = grado.nivel;

            const [distritosData, unidadesData, gradosData, areasData] = await Promise.all([
                CatalogService.getDistritos(depto.id),
                CatalogService.getUnidades(dist.id),
                CatalogService.getGrados(nivel.id),
                CatalogService.getAreasByGrado(grado.id)
            ]);

            // Set catalogs first
            setDistritos(distritosData);
            setUnidades(unidadesData);
            setGrados(gradosData);
            setAreasConocimiento(areasData);

            // Set IDs
            setEditingAreaId(fullArea.id);
            setSelectedDepto(depto.id);
            setSelectedDistrito(dist.id);
            setSelectedNivel(nivel.id);
            setSelectedGrado(grado.id);

            setFormData({
                unidad_educativa_id: fullArea.unidad_educativa.id,
                area_conocimiento_id: fullArea.area_conocimiento.id,
                turno_id: fullArea.turno.id,
                paralelos_ids: fullArea.paralelos.map(p => p.id)
            });

            setShowModal(true);
        } catch (error) {
            console.error('Error loading area for edit:', error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDelete = async (id: string) => {
        if (!confirm('┬┐Est├ís seguro de eliminar esta ├írea? Se borrar├ín las planificaciones asociadas.')) return;
        const success = await AreasService.deleteArea(id);
        if (success) {
            setAreas(areas.filter(a => a.id !== id));
        } else {
            alert('Error al eliminar');
        }
    };

    const toggleParalelo = (id: string) => {
        setFormData(prev => {
            const exists = prev.paralelos_ids.includes(id);
            if (exists) {
                return { ...prev, paralelos_ids: prev.paralelos_ids.filter(p => p !== id) };
            } else {
                return { ...prev, paralelos_ids: [...prev.paralelos_ids, id] };
            }
        });
    };

    if (isLoading) return <div className="p-8"><div className="animate-pulse h-8 w-48 bg-slate-200 rounded mb-4"></div></div>;

    return (
        <div className="p-6 space-y-8 animate-in fade-in duration-500">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        <span className="p-2 bg-blue-100 text-blue-600 rounded-lg"><IconSchool /></span>
                        ├üreas de Trabajo
                    </h1>
                    <p className="text-slate-500 mt-1">Gestiona tus clases, materias y paralelos asignados.</p>
                </div>
                <Button onClick={() => { resetForm(); setShowModal(true); }} className="bg-blue-600 hover:bg-blue-700 gap-2">
                    <IconAdd />
                    Nueva Clase
                </Button>
            </div>

            {/* List Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {areas.length === 0 && (
                    <div className="col-span-full py-12 text-center text-slate-400 bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                        <IconSchool />
                        <p className="mt-2">No tienes ├íreas de trabajo asignadas.</p>
                        <Button variant="ghost" onClick={() => setShowModal(true)}>Crear la primera</Button>
                    </div>
                )}

                {areas.map(area => (
                    <div
                        key={area.id}
                        onClick={() => handleEdit(area)}
                        className="bg-white rounded-xl border border-slate-200 shadow-sm hover:shadow-md hover:border-blue-300 transition-all p-5 group relative cursor-pointer"
                    >
                        <div className="absolute top-4 right-4 flex gap-1 z-10">
                            <button
                                onClick={(e) => {
                                    e.stopPropagation();
                                    handleDelete(area.id);
                                }}
                                className="p-2 opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-50 rounded-full text-red-500"
                            >
                                <IconDelete />
                            </button>
                        </div>

                        <div className="mb-4">
                            <span className="text-xs font-bold text-blue-600 bg-blue-50 px-2 py-1 rounded-md uppercase tracking-wider">
                                {area.unidad_educativa?.nombre}
                            </span>
                        </div>

                        <h3 className="text-lg font-bold text-slate-900 mb-1 line-clamp-1 group-hover:text-blue-600 transition-colors">
                            {area.area_conocimiento?.nombre}
                        </h3>
                        <p className="text-xs text-slate-400 font-medium">
                            {(area.area_conocimiento as any).grado?.nombre} ÔÇó {(area.area_conocimiento as any).grado?.nivel?.nombre}
                        </p>

                        <div className="flex flex-wrap gap-4 mt-4 text-sm text-slate-600">
                            <div className="flex items-center gap-1.5">
                                <IconSchedule />
                                <span>{area.turno?.nombre}</span>
                            </div>
                            <div className="flex items-center gap-1.5">
                                <IconGroup />
                                <div className="flex gap-1">
                                    {area.paralelos?.map(p => (
                                        <span key={p.id} className="font-bold bg-slate-100 px-1.5 rounded text-slate-800">
                                            {p.nombre}
                                        </span>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            {/* Modal */}
            {showModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-in fade-in duration-200">
                    <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md flex flex-col max-h-[90vh] overflow-hidden animate-in zoom-in-95 duration-200">
                        {/* Header Fijo */}
                        <div className="p-6 pb-4 border-b border-slate-100">
                            <h2 className="text-xl font-bold text-slate-900">{editingAreaId ? 'Editar Clase' : 'Nueva Clase'}</h2>
                        </div>

                        {/* Contenido Desplazable */}
                        <div className="flex-1 overflow-y-auto p-6 space-y-6">

                            <div className="space-y-4">
                                {/* Selecci├│n Jer├írquica: Departamento -> Distrito -> Unidad */}
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Departamento</label>
                                        <select
                                            className="w-full p-2.5 rounded-lg border border-slate-200 bg-slate-50 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                                            value={selectedDepto}
                                            onChange={e => setSelectedDepto(e.target.value ? Number(e.target.value) : '')}
                                        >
                                            <option value="">Seleccionar...</option>
                                            {departamentos.map(d => (
                                                <option key={d.id} value={d.id}>{d.nombre}</option>
                                            ))}
                                        </select>
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Distrito</label>
                                        <select
                                            className="w-full p-2.5 rounded-lg border border-slate-200 bg-slate-50 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                                            value={selectedDistrito}
                                            onChange={e => setSelectedDistrito(e.target.value ? Number(e.target.value) : '')}
                                            disabled={!selectedDepto}
                                        >
                                            <option value="">{selectedDepto ? 'Seleccionar...' : 'Elige Depto'}</option>
                                            {distritos.map(d => (
                                                <option key={d.id} value={d.id}>{d.nombre}</option>
                                            ))}
                                        </select>
                                    </div>
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-1">Unidad Educativa</label>
                                    <select
                                        className="w-full p-2.5 rounded-lg border border-slate-200 bg-slate-50 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                                        value={formData.unidad_educativa_id}
                                        onChange={e => setFormData({ ...formData, unidad_educativa_id: e.target.value ? Number(e.target.value) : '' })}
                                        disabled={!selectedDistrito}
                                    >
                                        <option value="">{selectedDistrito ? 'Seleccionar...' : 'Elige un Distrito primero'}</option>
                                        {unidades.map(u => (
                                            <option key={u.id} value={u.id}>{u.nombre}</option>
                                        ))}
                                    </select>
                                </div>

                                {/* Nivel y Grado */}
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Nivel</label>
                                        <select
                                            className="w-full p-2.5 rounded-lg border border-slate-200 bg-slate-50 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                                            value={selectedNivel}
                                            onChange={e => setSelectedNivel(e.target.value ? Number(e.target.value) : '')}
                                        >
                                            <option value="">Seleccionar...</option>
                                            {niveles.map(n => (
                                                <option key={n.id} value={n.id}>{n.nombre}</option>
                                            ))}
                                        </select>
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-slate-700 mb-1">Grado</label>
                                        <select
                                            className="w-full p-2.5 rounded-lg border border-slate-200 bg-slate-50 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                                            value={selectedGrado}
                                            onChange={e => setSelectedGrado(e.target.value ? Number(e.target.value) : '')}
                                            disabled={!selectedNivel}
                                        >
                                            <option value="">{selectedNivel ? 'Seleccionar...' : 'Elige un Nivel primero'}</option>
                                            {grados.map(g => (
                                                <option key={g.id} value={g.id}>{g.nombre}</option>
                                            ))}
                                        </select>
                                    </div>
                                </div>

                                {/* ├ürea */}
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-1">├ürea de Conocimiento</label>
                                    <select
                                        className="w-full p-2.5 rounded-lg border border-slate-200 bg-slate-50 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                                        value={formData.area_conocimiento_id}
                                        onChange={e => setFormData({ ...formData, area_conocimiento_id: e.target.value ? Number(e.target.value) : '' })}
                                        disabled={!selectedGrado}
                                    >
                                        <option value="">{selectedGrado ? 'Seleccionar...' : 'Elige un Grado primero'}</option>
                                        {areasConocimiento.map(a => (
                                            <option key={a.id} value={a.id}>{a.nombre}</option>
                                        ))}
                                    </select>
                                </div>

                                {/* Turno */}
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-1">Turno</label>
                                    <select
                                        className="w-full p-2.5 rounded-lg border border-slate-200 bg-slate-50 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                                        value={formData.turno_id}
                                        onChange={e => setFormData({ ...formData, turno_id: e.target.value })}
                                    >
                                        <option value="">Seleccionar...</option>
                                        {turnos.map(t => (
                                            <option key={t.id} value={t.id}>{t.nombre}</option>
                                        ))}
                                    </select>
                                </div>

                                {/* Paralelos */}
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-2">Paralelos</label>
                                    <div className="flex flex-wrap gap-2">
                                        {paralelos.map(p => {
                                            const isSelected = formData.paralelos_ids.includes(p.id);
                                            return (
                                                <button
                                                    key={p.id}
                                                    onClick={() => toggleParalelo(p.id)}
                                                    className={`px-3 py-1.5 rounded-lg text-sm font-bold transition-all border ${isSelected
                                                        ? 'bg-blue-600 text-white border-blue-600 shadow-md transform scale-105'
                                                        : 'bg-white text-slate-600 border-slate-200 hover:border-blue-300'
                                                        }`}
                                                >
                                                    {p.nombre}
                                                </button>
                                            );
                                        })}
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Footer Fijo */}
                        <div className="p-6 pt-4 border-t border-slate-100 flex justify-end gap-3 bg-slate-50/50">
                            <Button variant="ghost" onClick={() => setShowModal(false)} className="w-auto px-6 py-2.5 shadow-none">
                                Cancelar
                            </Button>
                            <Button
                                className="w-auto px-8 py-2.5 bg-blue-600 hover:bg-blue-700 text-white shadow-lg shadow-blue-500/30"
                                onClick={handleSave}
                                isLoading={isSaving}
                                disabled={!formData.unidad_educativa_id || !formData.area_conocimiento_id || !formData.turno_id || formData.paralelos_ids.length === 0}
                            >
                                Guardar
                            </Button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

