import { useEffect, useState } from 'react';
import { AreasService, AreaTrabajo } from '@/services/areas.service';
import { CatalogService } from '@/services/catalog.service';
import { AuthService } from '@/services/auth.service';
import { Button } from '@/components/ui/button';

// Icons mapping for the 6 moments
const MOMENTS = [
    { id: 'objectives', label: 'Objetivos Estrat├®gicos', icon: 'target', color: 'bg-blue-500', href: '/dashboard/objectives' },
    { id: 'methodology', label: 'Momentos del Proceso Formativo', icon: 'history_edu', color: 'bg-purple-500', href: '/dashboard/methodology' },
    { id: 'resources', label: 'Recursos', icon: 'inventory_2', color: 'bg-green-500', href: '/dashboard/resources' },
    { id: 'periods', label: 'Periodos', icon: 'schedule', color: 'bg-orange-500', href: '/dashboard/periods' },
    { id: 'evaluation', label: 'Criterios de Evaluaci├│n', icon: 'assignment_turned_in', color: 'bg-indigo-500', href: '/dashboard/evaluation' },
    { id: 'curriculum', label: 'Adaptaci├│n Curricular', icon: 'edit_note', color: 'bg-rose-500', href: '/dashboard/curriculum' },
];


export default function PdcDesignPage() {
    const [step, setStep] = useState<'level' | 'areas'>('level');
    const [levels, setLevels] = useState<{ id: string; nombre: string }[]>([]);
    const [selectedLevel, setSelectedLevel] = useState<string | null>(null);
    const [areas, setAreas] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        loadLevels();
    }, []);

    const loadLevels = async () => {
        try {
            const data = await CatalogService.getNiveles();
            setLevels(data);
        } catch (error) {
            console.error('Error loading levels:', error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleSelectLevel = async (levelId: string) => {
        setSelectedLevel(levelId);
        setIsLoading(true);
        try {
            const { data: { session } } = await AuthService.getSession();
            if (session?.user) {
                const allAreas = await AreasService.getAreas(session.user.id);
                // Filter areas by level
                const filtered = allAreas.filter((area: any) =>
                    area.area_conocimiento?.grado?.nivel?.id === levelId
                );
                setAreas(filtered);
                setStep('areas');
            }
        } catch (error) {
            console.error('Error loading areas:', error);
        } finally {
            setIsLoading(false);
        }
    };

    if (isLoading && step === 'level') {
        return <div className="p-8 animate-pulse text-slate-400">Cargando niveles...</div>;
    }

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            {/* Header */}
            <div className="flex flex-col gap-2">
                <h1 className="text-3xl font-black text-slate-900">Dise├▒o del PDC</h1>
                <p className="text-slate-500 font-medium">
                    {step === 'level'
                        ? 'Selecciona el tipo de PDC que deseas dise├▒ar.'
                        : `Planificaci├│n para el nivel ${levels.find(l => l.id === selectedLevel)?.nombre}`}
                </p>
            </div>

            {step === 'level' && (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    {levels.map((level) => (
                        <button
                            key={level.id}
                            onClick={() => handleSelectLevel(level.id)}
                            className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-xl hover:scale-[1.02] transition-all group flex flex-col items-center text-center gap-4"
                        >
                            <div className="size-16 rounded-2xl bg-blue-50 text-blue-600 flex items-center justify-center group-hover:bg-blue-600 group-hover:text-white transition-colors">
                                <span className="material-symbols-rounded text-3xl">
                                    {level.nombre.includes('Inicial') ? 'child_care' : level.nombre.includes('Primaria') ? 'school' : 'history_edu'}
                                </span>
                            </div>
                            <div>
                                <h3 className="text-xl font-bold text-slate-900">{level.nombre}</h3>
                                <p className="text-sm text-slate-400 mt-1 font-medium">Dise├▒ar PDC para este nivel</p>
                            </div>
                        </button>
                    ))}
                </div>
            )}



            {step === 'areas' && (
                <div className="space-y-8">
                    <div className="flex justify-between items-center">
                        <Button variant="ghost" onClick={() => setStep('level')} className="gap-2 text-slate-500">
                            <span className="material-symbols-rounded">arrow_back</span>
                            Cambiar Nivel
                        </Button>
                        <Button className="bg-blue-600 shadow-lg shadow-blue-500/20 gap-2">
                            <span className="material-symbols-rounded">auto_awesome</span>
                            Generar Mi PDC
                        </Button>
                    </div>

                    <div className="grid grid-cols-1 gap-8">
                        {areas.length === 0 ? (
                            <div className="bg-slate-50 border-2 border-dashed border-slate-200 rounded-[2rem] p-12 text-center">
                                <p className="text-slate-400 font-medium">No tienes ├íreas de trabajo en este nivel.</p>
                                <Button onClick={() => window.location.href = '/dashboard/areas'} variant="ghost" className="text-blue-600 mt-2 font-bold">
                                    Configurar ├üreas de Trabajo
                                </Button>
                            </div>
                        ) : (
                            areas.map((area) => (
                                <div key={area.id} className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden group hover:shadow-md transition-shadow">
                                    <div className="p-6 md:p-8 border-b border-slate-50 flex flex-col md:flex-row md:items-center justify-between gap-4">
                                        <div>
                                            <span className="text-xs font-black text-blue-600 bg-blue-50 px-3 py-1 rounded-full uppercase tracking-widest mb-2 inline-block">
                                                {area.unidad_educativa?.nombre}
                                            </span>
                                            <h3 className="text-2xl font-black text-slate-900 uppercase">
                                                {area.area_conocimiento?.nombre}
                                            </h3>
                                            <p className="text-slate-400 font-bold text-sm mt-1 uppercase tracking-tight">
                                                {area.area_conocimiento?.grado?.nombre} ÔÇó {area.turno?.nombre}
                                            </p>
                                        </div>
                                        <div className="flex gap-2">
                                            <Button
                                                onClick={() => window.location.href = `/dashboard/pdc/new?areaId=${area.id}`}
                                                className="bg-slate-900 text-white rounded-2xl hover:bg-slate-800 transition-all font-bold px-6"
                                            >
                                                Generar PDC
                                            </Button>
                                        </div>
                                    </div>

                                    {/* Timeline */}
                                    <div className="p-6 md:p-8 bg-slate-50/50">
                                        <div className="relative">
                                            {/* Line */}
                                            <div className="absolute top-1/2 left-0 w-full h-1 bg-slate-200 -translate-y-1/2 hidden md:block" />

                                            <div className="grid grid-cols-2 md:grid-cols-6 gap-4 relative">
                                                {MOMENTS.map((moment, i) => (
                                                    <button
                                                        key={moment.id}
                                                        onClick={() => window.location.href = `${moment.href}?areaId=${area.id}`}
                                                        className="flex flex-col items-center text-center gap-3 group/item cursor-pointer outline-none"
                                                    >
                                                        <div className={`size-12 rounded-2xl ${moment.color} text-white flex items-center justify-center shadow-lg transform group-hover/item:scale-110 group-hover/item:rotate-3 transition-all z-10`}>
                                                            <span className="material-symbols-rounded text-xl">{moment.icon}</span>
                                                        </div>
                                                        <div className="space-y-1">
                                                            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Paso {i + 1}</p>
                                                            <p className="text-xs font-bold text-slate-700 leading-tight group-hover/item:text-blue-600 transition-colors">
                                                                {moment.label}
                                                            </p>
                                                        </div>
                                                    </button>
                                                ))}
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import { WizardProvider, useWizard } from '@/context/wizard-context';
import { Step1Referenciales } from '@/components/pdc/steps/step1-referenciales';
import { Step2TituloPsp } from '@/components/pdc/steps/step2-titulo-psp';
import { Step3Contenidos } from '@/components/pdc/steps/step3-contenidos';
import { Step4Metodologia } from '@/components/pdc/steps/step4-metodologia';
import { Step5Evaluacion } from '@/components/pdc/steps/step5-evaluacion';
import { useEffect, useState } from 'react';
import { useSearchParams } from 'next/navigation';
import { AreasService } from '@/services/areas.service';

function WizardContent() {
    const { step, setStep, updateData } = useWizard();
    const searchParams = useSearchParams();
    const areaId = searchParams.get('areaId');
    const [isLoading, setIsLoading] = useState(true);
    const [hasJumped, setHasJumped] = useState(false);

    useEffect(() => {
        if (areaId) {
            loadAreaData(areaId);
        } else {
            setIsLoading(false);
        }
    }, [areaId]);

    const loadAreaData = async (id: string) => {
        try {
            const area = await AreasService.getAreaById(id);
            if (area) {
                updateData({
                    areaId: id,
                    unidadEducativa: area.unidad_educativa?.nombre || '',
                    nivel: area.area_conocimiento?.grado?.nivel?.nombre || '',
                    grado: area.area_conocimiento?.grado?.nombre || '',
                    area: area.area_conocimiento?.nombre || '',
                });

                // Auto-jump to Step 3 for Intelligent Flow
                if (!hasJumped) {
                    setStep(3);
                    setHasJumped(true);
                }
            }
        } catch (error) {
            console.error('Error loading area data for wizard:', error);
        } finally {
            setIsLoading(false);
        }
    };

    const STEPS = [
        { num: 1, label: 'Datos Generales' },
        { num: 2, label: 'T├¡tulo & PSP' },
        { num: 3, label: 'Planificaci├│n' },
        { num: 4, label: 'Metodolog├¡a' },
        { num: 5, label: 'Evaluaci├│n' },
    ];

    if (isLoading) {
        return (
            <div className="max-w-4xl mx-auto py-20 text-center">
                <div className="size-16 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin mx-auto mb-4" />
                <p className="text-slate-500 font-bold animate-pulse">Preparando tu planificador...</p>
            </div>
        );
    }

    return (
        <div className="max-w-4xl mx-auto">
            {/* Header & Stepper */}
            <div className="mb-10 text-center">
                <h1 className="text-3xl font-black text-slate-900 mb-2 uppercase tracking-tight">Nuevo PDC</h1>
                <p className="text-slate-500 font-medium text-sm">Completa los pasos para generar tu planificaci├│n.</p>
            </div>

            {/* Progress Bar & Stepper Labels */}
            <div className="mb-12">
                <div className="flex justify-between relative px-2">
                    {/* Background Track */}
                    <div className="absolute top-full left-0 w-full h-1 bg-slate-100 -z-10 rounded-full translate-y-2" />
                    {/* Active Track */}
                    <div
                        className="absolute top-full left-0 h-1 bg-blue-500 -z-10 rounded-full transition-all duration-700 translate-y-2 shadow-[0_0_10px_rgba(59,130,246,0.3)]"
                        style={{ width: `${((step - 1) / (STEPS.length - 1)) * 100}%` }}
                    />

                    {STEPS.map((s) => (
                        <div
                            key={s.num}
                            onClick={() => setStep(s.num)}
                            className="flex flex-col items-center gap-2 cursor-pointer group"
                        >
                            <span className={`text-[10px] font-black uppercase tracking-[0.15em] transition-all duration-300 ${step >= s.num ? 'text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}>
                                {s.label}
                            </span>
                            {/* Marker dot */}
                            <div className={`size-2.5 rounded-full border-2 transition-all duration-500 translate-y-3.5 ${step >= s.num ? 'bg-blue-500 border-white scale-125 shadow-md' : 'bg-white border-slate-200 bg-slate-50'
                                }`} />
                        </div>
                    ))}
                </div>
            </div>

            {/* Dynamic Step Content */}
            <div className="glass-card p-1 md:p-8 rounded-[2rem] shadow-xl shadow-slate-200/40 min-h-[500px]">
                {step === 1 && <Step1Referenciales />}
                {step === 2 && <Step2TituloPsp />}
                {step === 3 && <Step3Contenidos />}
                {step === 4 && <Step4Metodologia />}
                {step === 5 && <Step5Evaluacion />}
            </div>
        </div>
    );
}

export default function NewPDCPage() {
    return (
        <WizardProvider>
            <WizardContent />
        </WizardProvider>
    );
}

