                        </p>
                        <button
                            onClick={() => router.push('/dashboard/areas')}
                            className="text-blue-600 font-black text-xs uppercase tracking-widest hover:underline"
                        >
                            Ir a Configuraci├│n
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import { ProfileService, UserProfile } from '@/services/profile.service';
import { AuthService } from '@/services/auth.service';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';

export default function ProfilePage() {
    const [profile, setProfile] = useState<UserProfile | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'success'>('idle');

    // Form States
    const [formData, setFormData] = useState({
        nombres: '',
        apellidos: '',
        titulo: '',
        celular: ''
    });

    useEffect(() => {
        loadProfile();
    }, []);

    const loadProfile = async () => {
        try {
            // Safety timeout to prevent infinite loading
            const timeout = setTimeout(() => setIsLoading(false), 5000);

            const { data: { session } } = await AuthService.getSession();
            if (session?.user) {
                const data = await ProfileService.getProfile(session.user.id);

                // If data exists, use it. If not, create default from session.
                const profileData = data || {
                    id: session.user.id,
                    email: session.user.email || '',
                    nombres: '',
                    apellidos: '',
                    titulo: '',
                    celular: '',
                    creditos: 0,
                    roles: ['Profesor'],
                    estado_completitud: false
                };

                setProfile(profileData as UserProfile);

                setFormData({
                    nombres: profileData.nombres || '',
                    apellidos: profileData.apellidos || '',
                    titulo: profileData.titulo || '',
                    celular: profileData.celular || ''
                });
            } else {
                // If no session, redirect to login
                window.location.href = '/login';
            }
            clearTimeout(timeout);
        } catch (error) {
            console.error('Error loading profile:', error);
        } finally {
            setIsLoading(false);
        }
    };

    const [errorMessage, setErrorMessage] = useState('');

    const handleSave = async () => {
        if (!profile) return;
        setSaveStatus('saving');
        setErrorMessage('');

        try {
            // Determine if profile is complete
            const isComplete = Boolean(
                formData.nombres?.trim() &&
                formData.apellidos?.trim() &&
                formData.titulo?.trim() &&
                formData.celular?.trim()
            );

            const { success, error } = await ProfileService.updateProfile(profile.id, {
                ...formData,
                email: profile.email, // Include email to satisfy NOT NULL constraint on upsert
                estado_completitud: isComplete
            });

            if (success) {
                setSaveStatus('success');
                // If complete, redirect to dashboard main view after a short delay
                if (isComplete) {
                    setTimeout(() => {
                        window.location.href = '/dashboard';
                    }, 1000);
                } else {
                    setTimeout(() => setSaveStatus('idle'), 2000);
                    await loadProfile(); // Force await to ensure UI updates
                }
            } else {
                setSaveStatus('idle');
                setErrorMessage(error || 'Error desconocido al guardar');
            }
        } catch (error: any) {
            console.error('Error saving:', error);
            setSaveStatus('idle');
            setErrorMessage(error.message || 'Error cr├¡tico en el cliente');
        }
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center min-h-[50vh]">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-slate-900"></div>
            </div>
        );
    }

    return (
        <div className="max-w-3xl mx-auto p-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Header */}
            <div className="mb-10 text-center">
                <h1 className="text-3xl font-black text-slate-800 tracking-tight mb-2">Mi Perfil</h1>
                <p className="text-slate-500 font-medium">Personaliza tu informaci├│n para tus documentos.</p>
            </div>

            {/* Main Card */}
            <div className="bg-white rounded-[2rem] shadow-xl shadow-slate-200/50 overflow-hidden border border-slate-100">

                {/* Hero / Cover */}
                <div className="h-40 bg-gradient-to-r from-blue-600 via-indigo-600 to-purple-600 relative">
                    <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10"></div>
                </div>

                <div className="px-10 pb-10 relative">
                    {/* Avatar Container */}
                    <div className="flex flex-col items-center -mt-16 mb-8">
                        <div className="relative group cursor-pointer">
                            <div className="h-32 w-32 rounded-full border-[6px] border-white bg-slate-100 shadow-lg overflow-hidden transition-transform transform group-hover:scale-105">
                                <img
                                    src={profile?.foto_url || `https://api.dicebear.com/9.x/avataaars/svg?seed=${formData.nombres || 'User'}`}
                                    alt="Avatar"
