'use client';

import { useWizard } from '@/context/wizard-context';
import { Button } from '@/components/ui/button';
import { useState, useEffect } from 'react';
import { LibraryService, UserContent } from '@/services/library.service';
import { useSearchParams } from 'next/navigation';

export function Step3Contenidos() {
    const searchParams = useSearchParams();
    const areaId = searchParams.get('areaId');
    const { data, updateData, nextStep, prevStep } = useWizard();
    const [userContents, setUserContents] = useState<UserContent[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [selected, setSelected] = useState<number[]>(data.contenidosSeleccionados || []);
    const [activeWeek, setActiveWeek] = useState<number>(1);
    const [mapping, setMapping] = useState<Record<number, number[]>>(data.mapContentsByWeek || { 1: [], 2: [], 3: [], 4: [] });

    useEffect(() => {
        if (areaId) {
            loadUserContents();
        }
    }, [areaId]);

    const loadUserContents = async () => {
        setLoading(true);
        const contents = await LibraryService.getUserContents(areaId!);
        setUserContents(contents);
        setLoading(false);
    };

    const toggleContent = (id: number) => {
        // If already selected, remove from everywhere
        if (selected.includes(id)) {
            const newSelected = selected.filter(c => c !== id);
            const newMapping = { ...mapping };
            Object.keys(newMapping).forEach(week => {
                newMapping[Number(week)] = newMapping[Number(week)].filter(c => c !== id);
            });
            setSelected(newSelected);
            setMapping(newMapping);
            updateData({ contenidosSeleccionados: newSelected, mapContentsByWeek: newMapping });
        } else {
            // Add to selected and active week
            const newSelected = [...selected, id];
            const newMapping = { ...mapping };
            if (!newMapping[activeWeek]) newMapping[activeWeek] = [];
            newMapping[activeWeek] = [...newMapping[activeWeek], id];

            setSelected(newSelected);
            setMapping(newMapping);
            updateData({ contenidosSeleccionados: newSelected, mapContentsByWeek: newMapping });
        }
    };

    const removeFromWeek = (id: number, week: number) => {
        const newMapping = { ...mapping };
        newMapping[week] = newMapping[week].filter(c => c !== id);

        // Check if it's still assigned to ANY week
        const stillInAnyWeek = Object.values(newMapping).flat().includes(id);

        if (!stillInAnyWeek) {
            setSelected(selected.filter(c => c !== id));
            updateData({ contenidosSeleccionados: selected.filter(c => c !== id) });
        }

        setMapping(newMapping);
        updateData({ mapContentsByWeek: newMapping });
    };

    const themes = userContents.filter(c => !c.padre_id);
    const getSubthemes = (parentId: number) => userContents.filter(c => c.padre_id === parentId);

    const filteredThemes = themes.filter(t =>
        t.titulo.toLowerCase().includes(searchTerm.toLowerCase()) ||
        (t.subtitulo && t.subtitulo.toLowerCase().includes(searchTerm.toLowerCase()))
    );

    return (
        <div className="space-y-6 animate-in slide-in-from-right duration-500 max-w-[1200px] mx-auto">
