                <div className="absolute top-0 right-0 w-64 h-64 bg-white/10 rounded-full -mr-32 -mt-32 blur-3xl"></div>
                <h3 className="text-2xl font-black mb-2 flex items-center gap-3">
                    <span className="material-symbols-rounded text-3xl">event_note</span>
                    Planificaci├│n
                </h3>
                <p className="text-sm font-medium opacity-90 max-w-xl">
                    Selecciona tus contenidos a la izquierda y as├¡gnalos a las semanas correspondientes en tu cronograma a la derecha.
                </p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">

                {/* LEFT COLUMN: Mis Contenidos */}
                <div className="space-y-4">
                    <div className="flex items-center justify-between px-2">
                        <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest">Mis Contenidos</h4>
                        <span className="text-[10px] font-black text-blue-600 bg-blue-50 px-2.5 py-1 rounded-full uppercase">
                            Semana Activa: {activeWeek}
                        </span>
                    </div>

                    <div className="relative">
                        <span className="material-symbols-rounded absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">search</span>
                        <input
                            type="text"
                            placeholder="Filtrar por t├¡tulo..."
                            className="w-full bg-white border border-slate-100 rounded-2xl py-4 pl-12 pr-4 text-sm font-medium shadow-sm focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 outline-none transition-all"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>

                    <div className="grid gap-3 max-h-[600px] overflow-y-auto pr-2 custom-scrollbar p-1">
                        {loading ? (
                            <div className="py-20 text-center">
                                <div className="animate-spin size-8 border-4 border-blue-500 border-t-transparent rounded-full mx-auto mb-4"></div>
                                <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">Sincronizando biblioteca...</p>
                            </div>
                        ) : filteredThemes.length === 0 ? (
                            <div className="py-12 text-center bg-slate-50/50 rounded-3xl border-2 border-dashed border-slate-100">
                                <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">Sin resultados</p>
                            </div>
                        ) : (
                            filteredThemes.map(theme => {
                                const subs = getSubthemes(theme.id);
                                const isSelected = selected.includes(theme.id);

                                return (
                                    <div key={theme.id} className="space-y-2 mb-2">
                                        <div
                                            onClick={() => toggleContent(theme.id)}
                                            className={`p-5 rounded-2xl border transition-all duration-300 group cursor-pointer ${isSelected
                                                ? 'bg-blue-600 border-blue-600 shadow-lg shadow-blue-500/20 text-white translate-x-1'
                                                : 'bg-white border-slate-100 hover:border-blue-300 hover:shadow-md'
                                                }`}
                                        >
                                            <div className="flex items-center gap-4">
                                                <div className={`size-6 rounded-lg border-2 flex items-center justify-center transition-all ${isSelected ? 'bg-white border-white' : 'border-slate-200 bg-slate-50'}`}>
                                                    {isSelected && <span className="material-symbols-rounded text-blue-600 text-sm font-black">check</span>}
                                                </div>
                                                <div className="flex-1">
                                                    <h4 className={`font-black text-sm ${isSelected ? 'text-white' : 'text-slate-800'}`}>{theme.titulo}</h4>
                                                    {theme.subtitulo && <p className={`text-[10px] italic ${isSelected ? 'text-white/70' : 'text-slate-400'}`}>{theme.subtitulo}</p>}
                                                </div>
                                                {!isSelected && <span className="material-symbols-rounded opacity-0 group-hover:opacity-100 text-blue-400 transition-opacity">add_circle</span>}
                                            </div>
                                        </div>

                                        {subs.length > 0 && (
                                            <div className="ml-10 space-y-2 border-l-2 border-slate-100 pl-4 py-1">
                                                {subs.map(sub => {
                                                    const isSubSelected = selected.includes(sub.id);
                                                    return (
                                                        <div
                                                            key={sub.id}
                                                            onClick={() => toggleContent(sub.id)}
                                                            className={`p-4 rounded-xl border transition-all text-xs group cursor-pointer ${isSubSelected
                                                                ? 'bg-blue-50 border-blue-500 text-blue-900 shadow-sm'
                                                                : 'bg-white border-slate-50 hover:border-blue-200 text-slate-600'
                                                                }`}
                                                        >
                                                            <div className="flex items-center gap-3">
                                                                <div className={`size-4 rounded-md border flex items-center justify-center transition-all ${isSubSelected ? 'bg-blue-600 border-blue-600' : 'border-slate-200 bg-slate-50'}`}>
                                                                    {isSubSelected && <span className="material-symbols-rounded text-white text-[10px] font-black">check</span>}
                                                                </div>
                                                                <span className="font-black flex-1 uppercase tracking-tight">{sub.titulo}</span>
                                                            </div>
                                                        </div>
                                                    );
                                                })}
                                            </div>
                                        )}
                                    </div>
                                );
                            })
                        )}
                    </div>
                </div>

                {/* RIGHT COLUMN: Cronograma */}
                <div className="space-y-6">
                    <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest px-2">Cronograma Semanal</h4>

                    <div className="grid gap-4">
                        {[1, 2, 3, 4].map((week) => {
                            const contentsInWeek = mapping[week] || [];
                            const isActive = activeWeek === week;

                            return (
                                <div
                                    key={week}
                                    onClick={() => setActiveWeek(week)}
                                    className={`rounded-3xl border-2 transition-all p-6 relative group cursor-pointer ${isActive
                                        ? 'bg-white border-blue-600 shadow-2xl shadow-blue-500/10 ring-4 ring-blue-50'
                                        : 'bg-slate-50/50 border-transparent hover:bg-white hover:border-slate-200 shadow-sm'
                                        }`}
                                >
                                    <div className="flex items-center justify-between mb-4">
                                        <div className="flex items-center gap-3">
                                            <div className={`size-10 rounded-2xl flex items-center justify-center shadow-inner ${isActive ? 'bg-blue-600 text-white' : 'bg-slate-200 text-slate-500'}`}>
                                                <span className="text-lg font-black">{week}</span>
                                            </div>
                                            <div>
                                                <p className={`text-[10px] font-black uppercase tracking-widest ${isActive ? 'text-blue-600' : 'text-slate-400'}`}>Semana</p>
                                                <h5 className={`font-black uppercase text-xs tracking-tight ${isActive ? 'text-slate-900' : 'text-slate-500'}`}>Programaci├│n</h5>
                                            </div>
                                        </div>
                                        {isActive && <div className="size-2 rounded-full bg-blue-600 animate-ping"></div>}
                                    </div>

                                    <div className="space-y-2">
                                        {contentsInWeek.length === 0 ? (
                                            <div className="py-4 text-center border-2 border-dashed border-slate-200 rounded-2xl">
                                                <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Vac├¡o</p>
                                            </div>
                                        ) : (
                                            contentsInWeek.map(contentId => {
                                                const content = userContents.find(c => c.id === contentId);
                                                if (!content) return null;
                                                return (
                                                    <div
                                                        key={contentId}
                                                        className="flex items-center justify-between bg-white border border-slate-100 px-4 py-3 rounded-xl shadow-sm hover:border-blue-200 transition-colors group/item"
                                                    >
                                                        <div className="flex-1 min-w-0 pr-4">
                                                            <p className="text-xs font-black text-slate-800 truncate uppercase">{content.titulo}</p>
                                                            {content.subtitulo && <p className="text-[10px] text-slate-400 italic truncate">{content.subtitulo}</p>}
                                                        </div>
                                                        <button
                                                            onClick={(e) => {
                                                                e.stopPropagation();
                                                                removeFromWeek(contentId, week);
                                                            }}
                                                            className="text-slate-300 hover:text-red-500 transition-colors"
                                                        >
                                                            <span className="material-symbols-rounded text-lg font-black">close</span>
                                                        </button>
                                                    </div>
                                                );
                                            })
                                        )}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>

            {/* Actions Bar */}
            <div className="flex items-center justify-between pt-12 border-t border-slate-100 mt-12">
                <Button
                    variant="ghost"
                    onClick={prevStep}
                    className="px-8 rounded-2xl h-14 font-black text-xs uppercase tracking-widest text-slate-500 hover:bg-slate-50"
                >
                    <span className="material-symbols-rounded mr-2">arrow_back</span>
                    Volver
                </Button>
                <div className="flex items-center gap-6">
                    <div className="text-right hidden sm:block">
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Seleccionados</p>
                        <p className="text-xl font-black text-blue-600">{selected.length}</p>
                    </div>
                    <Button
                        onClick={nextStep}
                        disabled={selected.length === 0}
                        className="bg-blue-600 hover:bg-blue-700 px-12 rounded-2xl h-14 shadow-[0_10px_30px_-5px_rgba(59,130,246,0.3)] font-black text-xs uppercase tracking-widest text-white transition-all transform hover:scale-105 disabled:opacity-50 disabled:scale-100"
                    >
                        Continuar
                        <span className="material-symbols-rounded ml-2">keyboard_double_arrow_right</span>
                    </Button>
                </div>
            </div>
        </div>
    );
}

'use client';

import { useWizard } from '@/context/wizard-context';
import { Button } from '@/components/ui/button';
import { useState } from 'react';

const MOMENTOS = [
    { id: 'practica', label: 'Pr├íctica', icon: 'handyman', color: 'text-orange-600', bg: 'bg-orange-50', border: 'border-orange-100', accent: 'bg-orange-500' },
    { id: 'teoria', label: 'Teor├¡a', icon: 'menu_book', color: 'text-blue-600', bg: 'bg-blue-50', border: 'border-blue-100', accent: 'bg-blue-500' },
    { id: 'valoracion', label: 'Valoraci├│n', icon: 'balance', color: 'text-green-600', bg: 'bg-green-50', border: 'border-green-100', accent: 'bg-green-500' },
    { id: 'produccion', label: 'Producci├│n', icon: 'inventory_2', color: 'text-purple-600', bg: 'bg-purple-50', border: 'border-purple-100', accent: 'bg-purple-500' },
];

export function Step4Metodologia() {
    const { data, updateData, nextStep, prevStep } = useWizard();
    const [activeTab, setActiveTab] = useState('practica');

    const activeMomento = data.momentos?.find(m => m.tipo === activeTab);
    const selectedMomento = MOMENTOS.find(m => m.id === activeTab)!;

    const handleContentChange = (val: string) => {
        const currentMomentos = data.momentos || [];
        const existingIndex = currentMomentos.findIndex(m => m.tipo === activeTab);

        let newMomentos;
        if (existingIndex >= 0) {
            newMomentos = [...currentMomentos];
            newMomentos[existingIndex] = { ...newMomentos[existingIndex], descripcion: val };
        } else {
            const orden = MOMENTOS.findIndex(m => m.id === activeTab) + 1;
            newMomentos = [...currentMomentos, {
                tipo: activeTab as any,
                descripcion: val,
                orden
            }];
        }
        updateData({ momentos: newMomentos });
    };

    const handleAdaptacionesChange = (val: string) => {
        updateData({
            adaptaciones: {
                ...data.adaptaciones,
                descripcion: val
            }
        });
    };

    const handleRecursosChange = (val: string) => {
        const titles = val.split(',').map(t => t.trim()).filter(Boolean);
        const newRecursos = titles.map(t => ({
            titulo: t,
            tipo: 'Otro'
        }));
        updateData({ recursos: newRecursos });
    };

    const recursosString = data.recursos?.map(r => r.titulo).join(', ') || '';

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-right duration-500">
            {/* Header Banner */}
            <div className="bg-white rounded-[2rem] border border-slate-100 p-8 shadow-[0_10px_40px_-15px_rgba(0,0,0,0.05)]">
                <div className="flex items-center gap-4 mb-3">
                    <span className="p-3 bg-indigo-50 text-indigo-600 rounded-2xl material-symbols-rounded">psychology</span>
                    <h3 className="text-xl font-black text-slate-900 uppercase tracking-tight">Orientaciones Metodol├│gicas</h3>
                </div>
                <p className="text-sm text-slate-500 font-medium ml-1">
                    Dise├▒a la experiencia de aprendizaje a trav├®s de los cuatro momentos fundamentales.
                </p>
            </div>

            {/* Moments Navigation */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {MOMENTOS.map(m => {
                    const isActive = activeTab === m.id;
                    return (
                        <button
                            key={m.id}
                            onClick={() => setActiveTab(m.id)}
                            className={`flex flex-col items-start p-5 rounded-[1.5rem] border-2 transition-all duration-300 relative overflow-hidden group ${isActive
                                    ? `${m.bg} ${m.border} shadow-lg shadow-${m.color.split('-')[1]}-500/10`
                                    : 'bg-white border-slate-50 hover:border-slate-200'
                                }`}
                        >
                            <span className={`material-symbols-rounded mb-3 transition-transform duration-300 group-hover:scale-110 ${isActive ? m.color : 'text-slate-300'}`}>
                                {m.icon}
                            </span>
                            <span className={`text-[10px] font-black uppercase tracking-widest ${isActive ? m.color : 'text-slate-400'}`}>
                                Momento
                            </span>
                            <span className={`font-black uppercase text-xs tracking-tight ${isActive ? 'text-slate-900' : 'text-slate-500'}`}>
                                {m.label}
                            </span>
                            {isActive && <div className={`absolute bottom-0 left-0 h-1 w-full ${m.accent}`}></div>}
                        </button>
                    );
                })}
            </div>

            {/* Activity Editor */}
            <div className="space-y-6">
                <div className={`p-1 rounded-[2rem] border-2 ${selectedMomento.border} ${selectedMomento.bg} shadow-inner`}>
                    <div className="bg-white/80 backdrop-blur-md rounded-[1.8rem] p-6">
                        <div className="flex items-center justify-between mb-4">
                            <h4 className={`text-xs font-black uppercase tracking-widest ${selectedMomento.color}`}>
                                Actividades: {selectedMomento.label}
                            </h4>
                            <span className="text-[10px] font-bold text-slate-400">FASE ACTIVA</span>
                        </div>
                        <textarea
                            className="w-full bg-transparent border-none py-2 px-0 text-sm font-medium text-slate-800 placeholder:text-slate-300 outline-none resize-none min-h-[200px]"
                            placeholder={`Describe detalladamente el proceso de ${selectedMomento.label}...`}
                            value={activeMomento?.descripcion || ''}
                            onChange={(e) => handleContentChange(e.target.value)}
                        />
                    </div>
                </div>

                {/* Secondary Inputs Grid */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="bg-white rounded-[1.8rem] border border-slate-100 p-6 shadow-sm">
                        <div className="flex items-center gap-3 mb-4">
                            <span className="material-symbols-rounded text-slate-400 text-lg">category</span>
                            <label className="text-xs font-black text-slate-500 uppercase tracking-widest">Recursos y Materiales</label>
                        </div>
                        <input
                            className="w-full bg-slate-50 border-none rounded-xl py-4 px-5 text-sm font-bold text-slate-700 placeholder:text-slate-300 outline-none focus:ring-4 focus:ring-blue-500/5 transition-all"
                            placeholder="Ej. Gu├¡as, laptop, internet..."
                            value={recursosString}
                            onChange={(e) => handleRecursosChange(e.target.value)}
                        />
                    </div>

                    <div className="bg-white rounded-[1.8rem] border border-slate-100 p-6 shadow-sm">
                        <div className="flex items-center gap-3 mb-4">
                            <span className="material-symbols-rounded text-slate-400 text-lg">diversity_3</span>
                            <label className="text-xs font-black text-slate-500 uppercase tracking-widest">Adaptaciones Curriculares</label>
                        </div>
                        <input
                            className="w-full bg-slate-50 border-none rounded-xl py-4 px-5 text-sm font-bold text-slate-700 placeholder:text-slate-300 outline-none focus:ring-4 focus:ring-blue-500/5 transition-all"
                            placeholder="Describir si existen necesidades especiales..."
                            value={data.adaptaciones?.descripcion || ''}
                            onChange={(e) => handleAdaptacionesChange(e.target.value)}
                        />
                    </div>
                </div>
            </div>

            {/* Footer Actions */}
            <div className="flex items-center justify-between pt-10 border-t border-slate-100 border-dashed">
                <Button
                    variant="ghost"
                    onClick={prevStep}
                    className="px-8 rounded-2xl h-14 font-black text-xs uppercase tracking-widest text-slate-500 hover:bg-slate-50"
                >
                    <span className="material-symbols-rounded mr-2">arrow_back</span>
                    Volver
                </Button>
                <Button
                    onClick={nextStep}
                    className="bg-slate-900 border-2 border-slate-800 hover:bg-black px-12 rounded-2xl h-14 shadow-xl font-black text-xs uppercase tracking-widest text-white transition-all transform hover:scale-105"
                >
                    Continuar
                    <span className="material-symbols-rounded ml-2 font-black">arrow_forward</span>
                </Button>
            </div>
        </div>
    );
}

'use client';

import { useWizard } from '@/context/wizard-context';
import { Button } from '@/components/ui/button';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { PdcService } from '@/services/pdc.service';

const DIMENSIONES = [
    { id: 'ser', label: 'Ser', icon: 'favorite', color: 'text-amber-600', bg: 'bg-amber-50', border: 'border-amber-100', accent: 'bg-amber-500' },
    { id: 'saber', label: 'Saber', icon: 'lightbulb', color: 'text-blue-600', bg: 'bg-blue-50', border: 'border-blue-100', accent: 'bg-blue-500' },
    { id: 'hacer', label: 'Hacer', icon: 'auto_fix_high', color: 'text-emerald-600', bg: 'bg-emerald-50', border: 'border-emerald-100', accent: 'bg-emerald-500' },
];

export function Step5Evaluacion() {
    const { data, updateData, prevStep } = useWizard();
    const [isSaving, setIsSaving] = useState(false);
    const router = useRouter();

    const handleCriterionChange = (dimensionId: string, val: string) => {
        const currentCriterios = data.criteriosEvaluacion || [];
        const existingIndex = currentCriterios.findIndex(c => c.dimension === dimensionId);

        let newCriterios;
        if (existingIndex >= 0) {
            newCriterios = [...currentCriterios];
            newCriterios[existingIndex] = { ...newCriterios[existingIndex], descripcion: val };
        } else {
            const orden = DIMENSIONES.findIndex(d => d.id === dimensionId) + 1;
            newCriterios = [...currentCriterios, {
                dimension: dimensionId as any,
                descripcion: val
            }];
        }
        updateData({ criteriosEvaluacion: newCriterios });
    };

    const handleFinish = async () => {
        setIsSaving(true);
        try {
            const result = await PdcService.savePdc(data);
            if (result.success) {
                alert('┬íPDC Generado con ├ëxito!');
                router.push(`/dashboard/areas/${data.areaId}`);
            } else {
                alert('Error al guardar el PDC: ' + (result.error?.message || 'Error desconocido'));
            }
        } catch (error) {
            console.error('Error saving PDC:', error);
            alert('Hubo un error al guardar el PDC.');
        } finally {
            setIsSaving(false);
        }
