                </div>
                <p className="text-sm text-slate-500 font-medium ml-1">
                    Define los indicadores para evaluar el desarrollo integral de tus estudiantes.
                </p>
            </div>

            {/* Dimensions Grid */}
            <div className="grid gap-6">
                {DIMENSIONES.map(dim => {
                    const criterion = data.criteriosEvaluacion?.find(c => c.dimension === dim.id);
                    return (
                        <div key={dim.id} className={`p-1 rounded-[2rem] border-2 ${dim.border} ${dim.bg} shadow-sm group transition-all duration-300 hover:shadow-md`}>
                            <div className="bg-white/90 backdrop-blur-sm rounded-[1.8rem] p-6">
                                <div className="flex items-center gap-4 mb-4">
                                    <div className={`size-10 rounded-xl flex items-center justify-center ${dim.bg} ${dim.color} border ${dim.border} shadow-inner`}>
                                        <span className="material-symbols-rounded">{dim.icon}</span>
                                    </div>
                                    <div className="flex-1">
                                        <h4 className={`text-[10px] font-black uppercase tracking-widest ${dim.color}`}>Dimensi├│n</h4>
                                        <p className="font-black text-slate-900 uppercase tracking-tight">{dim.label}</p>
                                    </div>
                                    <div className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${criterion?.descripcion ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-slate-50 text-slate-400 border border-slate-100'}`}>
                                        {criterion?.descripcion ? 'Definido' : 'Pendiente'}
                                    </div>
                                </div>
                                <textarea
                                    className="w-full bg-slate-50 border-none rounded-2xl py-4 px-5 text-sm font-medium text-slate-700 placeholder:text-slate-300 outline-none focus:ring-4 focus:ring-blue-500/5 transition-all resize-none min-h-[100px]"
                                    placeholder={`Describe los criterios de evaluaci├│n para el ${dim.label}...`}
                                    value={criterion?.descripcion || ''}
                                    onChange={(e) => handleCriterionChange(dim.id, e.target.value)}
                                />
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* Summary Report Preview */}
            <div className="bg-slate-900 rounded-[2.5rem] p-10 text-white shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 right-0 w-96 h-96 bg-blue-600/20 rounded-full -mr-48 -mt-48 blur-3xl"></div>

                <div className="relative z-10">
                    <div className="flex items-center gap-3 mb-8 border-b border-white/10 pb-6">
                        <span className="material-symbols-rounded text-blue-400">task</span>
                        <h4 className="font-black uppercase tracking-widest text-sm">Resumen de Planificaci├│n</h4>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                        <div className="space-y-1">
                            <p className="text-[10px] font-black text-blue-400 uppercase tracking-widest">Unidad Educativa</p>
                            <p className="text-sm font-bold truncate">{data.unidadEducativa || 'ÔÇö'}</p>
                        </div>
                        <div className="space-y-1">
                            <p className="text-[10px] font-black text-blue-400 uppercase tracking-widest">Nivel y Grado</p>
                            <p className="text-sm font-bold">{data.nivel} ÔÇó {data.grado}</p>
                        </div>
                        <div className="space-y-1">
                            <p className="text-[10px] font-black text-blue-400 uppercase tracking-widest">Contenidos</p>
                            <p className="text-sm font-bold">{data.contenidosSeleccionados?.length || 0} items programados</p>
                        </div>
                        <div className="space-y-1">
                            <p className="text-[10px] font-black text-blue-400 uppercase tracking-widest">Estado</p>
                            <div className="flex items-center gap-2">
                                <div className="size-2 rounded-full bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]"></div>
                                <p className="text-sm font-bold uppercase tracking-tight">Listo para generar</p>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Footer Actions */}
            <div className="flex items-center justify-between pt-10 border-t border-slate-100 border-dashed">
                <Button
                    variant="ghost"
                    onClick={prevStep}
                    className="px-8 rounded-2xl h-14 font-black text-xs uppercase tracking-widest text-slate-500 hover:bg-slate-50"
                >
                    <span className="material-symbols-rounded mr-2">arrow_back</span>
                    Volver
                </Button>
                <Button
                    onClick={handleFinish}
                    disabled={isSaving}
                    className="bg-blue-600 hover:bg-blue-700 px-12 rounded-2xl h-14 shadow-[0_10px_40px_-10px_rgba(59,130,246,0.4)] font-black text-xs uppercase tracking-widest text-white transition-all transform hover:scale-105 disabled:opacity-50 disabled:scale-100"
                >
                    {isSaving ? (
                        <>
                            <div className="animate-spin size-4 border-2 border-white border-t-transparent rounded-full mr-2"></div>
                            Generando...
                        </>
                    ) : (
                        <>
                            Finalizar y Generar
                            <span className="material-symbols-rounded ml-2 font-black">check_circle</span>
                        </>
                    )}
                </Button>
            </div>
        </div>
    );
}

import { supabase } from '@/lib/supabase';

export interface SystemStats {
    totalUsers: number;
    totalUnits: number;
    totalPDCs: number;
}

export interface Unit {
    id: number;
    nombre: string;
    direccion: string;
    telefono: string;
    distrito_id: number;
    distrito?: {
        id: number;
        nombre: string;
        departamento?: { nombre: string }
    };
}

export interface District {
    id: number;
    nombre: string;
    departamento?: {
        nombre: string
    };
}

export const AdminService = {
    async getSystemStats(): Promise<{ stats: SystemStats | null; error?: string }> {
        try {
            // Run counts in parallel
            const [users, units, pdcs] = await Promise.all([
                supabase.from('perfiles').select('*', { count: 'exact', head: true }),
                supabase.from('unidades_educativas').select('*', { count: 'exact', head: true }),
                supabase.from('contenidos_usuario').select('*', { count: 'exact', head: true })
            ]);

            if (users.error) throw users.error;
            if (units.error) throw units.error;
            if (pdcs.error) throw pdcs.error;

            return {
                stats: {
                    totalUsers: users.count || 0,
                    totalUnits: units.count || 0,
                    totalPDCs: pdcs.count || 0
                }
            };
        } catch (error: any) {
            console.error('Error fetching system stats:', error);
            return { stats: null, error: error.message };
        }

    },

    // --- Unidades Educativas CRUD ---

    async getUnits(): Promise<{ data: Unit[]; error?: string }> {
        try {
            const { data, error } = await supabase
                .from('unidades_educativas')
                .select(`
                    id, 
                    nombre, 
                    direccion, 
                    telefono, 
                    distrito_id,
                    distrito:distritos(
                        id,
                        nombre, 
                        departamento:departamentos(nombre)
                    )
                `)
                .order('nombre');

            if (error) throw error;

            // Map data to ensure relations are objects, not arrays
            const mappedData = (data || []).map(u => ({
                ...u,
                distrito: Array.isArray(u.distrito) ? {
                    ...u.distrito[0],
                    departamento: Array.isArray(u.distrito[0]?.departamento)
                        ? u.distrito[0].departamento[0]
                        : u.distrito[0]?.departamento
                } : u.distrito
            })) as unknown as Unit[];

            return { data: mappedData };
        } catch (error: any) {
            console.error('Error fetching units:', error);
            return { data: [], error: error.message };
        }
    },

    async createUnit(unit: { id: number; nombre: string; direccion?: string; telefono?: string; distrito_id: number }) {
        const { data, error } = await supabase
            .from('unidades_educativas')
            .insert(unit)
            .select()
            .single();
        return { data, error };
    },

    async updateUnit(id: number, updates: Partial<{ nombre: string; direccion: string; telefono: string; distrito_id: number }>) {
        const { data, error } = await supabase
            .from('unidades_educativas')
            .update(updates)
            .eq('id', id)
            .select()
            .single();
        return { data, error };
    },

    async deleteUnit(id: number) {
        const { error } = await supabase
            .from('unidades_educativas')
            .delete()
            .eq('id', id);
        return { error };
    },

    // Helper to get districts for the form
    async getDistricts(): Promise<{ data: District[]; error?: any }> {
        const { data, error } = await supabase
            .from('distritos')
            .select('id, nombre, departamento:departamentos(nombre)')
            .order('nombre');

        const mappedData = (data || []).map(d => ({
            ...d,
            departamento: Array.isArray(d.departamento) ? d.departamento[0] : d.departamento
        })) as unknown as District[];

        return { data: mappedData, error };
    },

    // --- Usuarios y Roles ---

    async getUsers() {
        try {
            // 1. Get all profiles
            const { data: profiles, error: profilesError } = await supabase
                .from('perfiles')
                .select('*')
                .order('created_at', { ascending: false });

            if (profilesError) throw profilesError;

            // 2. Get all roles assignments
            const { data: allRoles, error: rolesError } = await supabase
                .from('perfil_roles')
                .select('perfil_id, rol_nombre');

            if (rolesError) throw rolesError;

            // 3. Merge roles into profiles
            const users = profiles.map(p => ({
                ...p,
                roles: allRoles
                    .filter((r: any) => r.perfil_id === p.id)
                    .map((r: any) => r.rol_nombre)
            }));

            return { data: users };
        } catch (error: any) {
            console.error('Error fetching users:', error);
            return { data: [], error: error.message };
        }
    },

    async getRoles() {
        const { data, error } = await supabase
            .from('roles')
            .select('nombre')
            .order('nombre');
        return { data: data?.map(r => r.nombre) || [], error };
    },

    async updateUserRoles(userId: string, roles: string[]) {
        try {
            // 1. Delete existing roles
            const { error: deleteError } = await supabase
                .from('perfil_roles')
                .delete()
                .eq('perfil_id', userId);

            if (deleteError) throw deleteError;

            // 2. Insert new roles
            if (roles.length > 0) {
                const toInsert = roles.map(r => ({
                    perfil_id: userId,
                    rol_nombre: r
                }));

                const { error: insertError } = await supabase
                    .from('perfil_roles')
                    .insert(toInsert);

                if (insertError) throw insertError;
            }

            return { success: true };
        } catch (error: any) {
            console.error('Error updating roles:', error);
            return { success: false, error: error.message };
        }
    }
};

import { supabase } from '@/lib/supabase';

export interface AreaTrabajo {
    id: string; // UUID
    profesor_id: string; // UUID
    unidad_educativa: {
        id: number;
        nombre: string;
        distrito?: {
            id: number;
            nombre: string;
            departamento?: { id: number; nombre: string; }
        }
    };
    area_conocimiento: {
        id: number;
        nombre: string;
        grado?: {
            id: number;
            nombre: string;
            nivel?: { id: number; nombre: string; }
        }
    };
    turno: { id: string; nombre: string; };
    paralelos: { id: string; nombre: string; }[];
    created_at?: string;
}

export interface Catalogs {
    unidades: { id: number; nombre: string; }[];
    areas: { id: number; nombre: string; }[];
    turnos: { id: string; nombre: string; }[];
    paralelos: { id: string; nombre: string; }[];
}

export const AreasService = {
    async getAreas(userId: string): Promise<AreaTrabajo[]> {
        const { data, error } = await supabase
            .from('areas_trabajo')
            .select(`
                id,
                profesor_id,
                unidad_educativa:unidades_educativas(id, nombre),
                area_conocimiento:areas_conocimiento(
                    id, 
                    nombre,
                    grado:grados(
                        id,
                        nombre,
                        nivel:niveles(id, nombre)
                    )
                ),
                turno:turnos(id, nombre),
                created_at
            `)
            .eq('profesor_id', userId)
            .order('created_at', { ascending: false });

        if (error) {
            console.error('Error fetching areas:', error);
            return [];
        }

        // Fetch parallels for each area
        // Note: Ideally this would be done in a single query with better Supabase typing/relationships
        // or a view. For now, we'll fetch them separately or loop.
        // A better way with PostgREST:
        // .select('..., paralelos:area_trabajo_paralelo(paralelo:paralelos(id, nombre))')

        const areasWithParalelos = await Promise.all(data.map(async (area: any) => {
            const { data: paralelosData } = await supabase
                .from('area_trabajo_paralelo')
                .select('paralelo:paralelos(id, nombre)')
                .eq('area_trabajo_id', area.id);

            return {
                ...area,
                paralelos: paralelosData?.map((p: any) => p.paralelo) || []
            };
        }));

        return areasWithParalelos;
    },

    async getCatalogs(): Promise<Catalogs> {
        // Run all in parallel
        const [unidades, areas, turnos, paralelos] = await Promise.all([
            supabase.from('unidades_educativas').select('id, nombre'),
            supabase.from('areas_conocimiento').select('id, nombre'),
            supabase.from('turnos').select('id, nombre'),
            supabase.from('paralelos').select('id, nombre').order('nombre')
        ]);

        return {
            unidades: unidades.data || [],
            areas: areas.data || [],
            turnos: turnos.data || [],
            paralelos: paralelos.data || []
        };
    },

    async createArea(data: {
        profesor_id: string;
        unidad_educativa_id: number;
        area_conocimiento_id: number;
        turno_id: string;
        paralelos_ids: string[];
    }): Promise<{ success: boolean; data?: any; error?: any }> {
        // 1. Create Area
        const { data: area, error: areaError } = await supabase
            .from('areas_trabajo')
            .insert({
                profesor_id: data.profesor_id,
                unidad_educativa_id: data.unidad_educativa_id,
                area_conocimiento_id: data.area_conocimiento_id,
                turno_id: data.turno_id
            })
            .select()
            .single();

        if (areaError) return { success: false, error: areaError };

        // 2. Link Parallels
        if (data.paralelos_ids.length > 0) {
            const paralelosInserts = data.paralelos_ids.map(pid => ({
                area_trabajo_id: area.id,
                paralelo_id: pid
            }));

            const { error: paralelosError } = await supabase
                .from('area_trabajo_paralelo')
                .insert(paralelosInserts);

            if (paralelosError) {
                // Should probably rollback area creation, but for MVP we log error
                console.error('Error adding parallels:', paralelosError);
                return { success: false, error: paralelosError };
            }
        }

        return { success: true, data: area };
    },

    async updateArea(id: string, data: {
        unidad_educativa_id: number;
        area_conocimiento_id: number;
        turno_id: string;
        paralelos_ids: string[];
    }): Promise<{ success: boolean; error?: any }> {
        // 1. Update Area
        const { error: areaError } = await supabase
            .from('areas_trabajo')
            .update({
                unidad_educativa_id: data.unidad_educativa_id,
                area_conocimiento_id: data.area_conocimiento_id,
                turno_id: data.turno_id
            })
            .eq('id', id);

        if (areaError) return { success: false, error: areaError };

        // 2. Update Parallels (Delete then Insert)
        const { error: deleteError } = await supabase
            .from('area_trabajo_paralelo')
            .delete()
            .eq('area_trabajo_id', id);

        if (deleteError) return { success: false, error: deleteError };

        if (data.paralelos_ids.length > 0) {
            const paralelosInserts = data.paralelos_ids.map(pid => ({
                area_trabajo_id: id,
                paralelo_id: pid
            }));

            const { error: paralelosError } = await supabase
                .from('area_trabajo_paralelo')
                .insert(paralelosInserts);

            if (paralelosError) return { success: false, error: paralelosError };
        }

        return { success: true };
    },

    async deleteArea(id: string): Promise<boolean> {
        const { error } = await supabase
            .from('areas_trabajo')
            .delete()
            .eq('id', id);

        return !error;
    },

    async getAreaById(id: string): Promise<AreaTrabajo | null> {
        const { data, error } = await supabase
            .from('areas_trabajo')
            .select(`
                id,
                profesor_id,
                unidad_educativa:unidades_educativas(
                    id, 
                    nombre,
                    distrito:distritos(
                        id,
                        nombre,
                        departamento:departamentos(id, nombre)
                    )
                ),
                area_conocimiento:areas_conocimiento(
                    id, 
                    nombre,
                    grado:grados(
                        id,
                        nombre,
                        nivel:niveles(id, nombre)
                    )
                ),
                turno:turnos(id, nombre),
                created_at
            `)
            .eq('id', id)
            .single();

        if (error || !data) {
            console.error('Error fetching area by id:', error);
            return null;
        }

        const { data: paralelosData } = await supabase
            .from('area_trabajo_paralelo')
            .select('paralelo:paralelos(id, nombre)')
            .eq('area_trabajo_id', data.id);

        return {
            ...data,
            paralelos: paralelosData?.map((p: any) => p.paralelo) || []
        } as any as AreaTrabajo;
    }
};

import { supabase } from '@/lib/supabase';

export interface ContentItem {
    id: number;
    titulo: string;
    padre_id?: number | null;
    orden: number;
    descripcion?: string;
    area_conocimiento?: {
        id: number;
        nombre: string;
        grado?: {
            id: number;
            nombre: string;
            nivel?: { id: number; nombre: string }
        }
    };
    is_base: boolean;
}

export interface UserContent {
    id: number;
    propietario_id: string;
    area_trabajo_id: string;
    origen_base_id?: number | null;
    padre_id?: number | null;
    titulo: string;
    orden: number;
    created_at: string;
    updated_at: string;
}

export const LibraryService = {
    async getNextUserContentId(): Promise<number> {
        const { data, error } = await supabase
            .from('contenidos_usuario')
            .select('id')
            .order('id', { ascending: false })
            .limit(1)
            .single();

        if (error && error.code !== 'PGRST116') { // PGRST116 is code for no rows found
            console.error('Error getting next user content ID:', error);
            throw error;
        }

        return (data?.id || 0) + 1;
    },

    async searchContents(query: string = '', areaConocimientoId?: number): Promise<ContentItem[]> {
        let queryBuilder = supabase
            .from('contenidos_base')
            .select(`
                id,
                titulo,
                area_conocimiento:areas_conocimiento(
                    id,
                    nombre,
                    grado:grados(
                        id,
                        nombre,
                        nivel:niveles(id, nombre)
                    )
                )
            `)
            .limit(50);

        if (query) {
            queryBuilder = queryBuilder.ilike('titulo', `%${query}%`);
        }

        if (areaConocimientoId) {
            queryBuilder = queryBuilder.eq('area_conocimiento_id', areaConocimientoId);
        }

        const { data, error } = await queryBuilder;

        if (error) {
            console.error('Error searching library:', error);
            return [];
        }

        return data.map((item: any) => ({
            ...item,
            is_base: true
        })) as ContentItem[];
    },

    async getBaseContentsByArea(areaConocimientoId: number): Promise<ContentItem[]> {
        const { data, error } = await supabase
            .from('contenidos_base')
            .select(`
                id,
                titulo,
                padre_id,
                orden,
                area_conocimiento:areas_conocimiento(
                    id,
                    nombre,
                    grado:grados(
                        id,
                        nombre,
                        nivel:niveles(id, nombre)
                    )
                )
            `)
            .eq('area_conocimiento_id', areaConocimientoId)
            .order('orden');

        if (error) {
            console.error('Error fetching base contents by area:', error);
            return [];
        }

        return data.map((item: any) => ({
            ...item,
            is_base: true
        })) as ContentItem[];
    },

    async getUserContents(areaTrabajoId: string): Promise<UserContent[]> {
        const { data, error } = await supabase
            .from('contenidos_usuario')
            .select('*')
            .eq('area_trabajo_id', areaTrabajoId)
            .order('orden');

        if (error) {
            console.error('Error fetching user contents:', error);
            return [];
        }

        return data as UserContent[];
    },

    async copyContentToUser(baseContentId: number, areaTrabajoId: string): Promise<{ success: boolean; data?: any; error?: any }> {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session?.user) return { success: false, error: 'No authenticated session' };

        // 1. Get base content details
        const { data: baseContent } = await supabase
            .from('contenidos_base')
            .select('*')
            .eq('id', baseContentId)
            .single();

        if (!baseContent) return { success: false, error: 'Base content not found' };

        // 2. Preserve hierarchy in individual copies
        let userPadreId = null;
        if (baseContent.padre_id) {
            const { data: existingUserPadre } = await supabase
                .from('contenidos_usuario')
                .select('id')
                .eq('area_trabajo_id', areaTrabajoId)
                .eq('origen_base_id', baseContent.padre_id)
                .single();

            if (existingUserPadre) {
                userPadreId = existingUserPadre.id;
            }
        }

        // 3. Generate Manual ID
        const nextId = await this.getNextUserContentId();

        // 4. Create user content
        const { data, error } = await supabase
            .from('contenidos_usuario')
            .insert({
                id: nextId,
                propietario_id: session.user.id,
                area_trabajo_id: areaTrabajoId,
                origen_base_id: baseContentId,
                padre_id: userPadreId,
                titulo: baseContent.titulo,
                orden: baseContent.orden
            })
            .select()
            .single();

        return { success: !error, data, error };
    },

    async updateUserContent(id: number, updates: { titulo?: string }): Promise<{ success: boolean; error?: any; count?: number }> {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session?.user) return { success: false, error: 'No authenticated session' };

        const { data, error } = await supabase
            .from('contenidos_usuario')
            .update(updates)
            .eq('id', id)
            .select();

        if (error) {
            console.error('Error updating user content:', error);
            return { success: false, error };
        }

        const count = data?.length || 0;
        if (count === 0) {
            console.warn('No rows updated. Check if the ID exists and if you have permissions (RLS).');
        }

        return { success: count > 0, count };
    },

    async deleteUserContent(id: number): Promise<boolean> {
        const { error } = await supabase
            .from('contenidos_usuario')
            .delete()
            .eq('id', id);

        return !error;
    },

    async clearUserContents(areaTrabajoId: string): Promise<boolean> {
        const { error } = await supabase
            .from('contenidos_usuario')
            .delete()
            .eq('area_trabajo_id', areaTrabajoId);

        if (error) {
            console.error('Error clearing user contents:', error);
            return false;
        }
        return true;
    },

    async createCustomContent(areaTrabajoId: string, titulo: string): Promise<{ success: boolean; data?: UserContent; error?: any }> {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session?.user) return { success: false, error: 'No authenticated session' };

        // Get max order
        const { data: maxOrderData } = await supabase
            .from('contenidos_usuario')
            .select('orden')
            .eq('area_trabajo_id', areaTrabajoId)
            .is('padre_id', null)
            .order('orden', { ascending: false })
            .limit(1)
            .single();

        const nextOrder = (maxOrderData?.orden || 0) + 1;
        const nextId = await this.getNextUserContentId();

        const { data, error } = await supabase
            .from('contenidos_usuario')
            .insert({
                id: nextId,
                propietario_id: session.user.id,
                area_trabajo_id: areaTrabajoId,
                titulo,
                orden: nextOrder
            })
            .select()
            .single();

        return { success: !error, data, error };
    },

    async createCustomSubtheme(areaTrabajoId: string, padreId: number, titulo: string): Promise<{ success: boolean; data?: UserContent; error?: any }> {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session?.user) return { success: false, error: 'No session' };

        // Get max order
        const { data: maxOrderData } = await supabase
            .from('contenidos_usuario')
            .select('orden')
            .eq('padre_id', padreId)
            .order('orden', { ascending: false })
            .limit(1)
            .single();

        const nextOrder = (maxOrderData?.orden || 0) + 1;
        const nextId = await this.getNextUserContentId();

        const { data, error } = await supabase
            .from('contenidos_usuario')
            .insert({
                id: nextId,
                propietario_id: session.user.id,
                area_trabajo_id: areaTrabajoId,
                padre_id: padreId,
                titulo,
                orden: nextOrder
            })
            .select()
            .single();

        return { success: !error, data, error };
    },

    async reorderUserContent(id1: number, order1: number, id2: number, order2: number): Promise<boolean> {
        const { error: error1 } = await supabase
            .from('contenidos_usuario')
            .update({ orden: order2 })
            .eq('id', id1);

        const { error: error2 } = await supabase
            .from('contenidos_usuario')
            .update({ orden: order1 })
            .eq('id', id2);

        return !error1 && !error2;
    },

    async copyAllBaseContentsToUser(areaConocimientoId: number, areaTrabajoId: string): Promise<{ success: boolean; error?: any }> {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session?.user) return { success: false, error: 'No session' };

        // 1. Fetch all base contents
        const { data: baseContents, error: fetchError } = await supabase
            .from('contenidos_base')
            .select('*')
            .eq('area_conocimiento_id', areaConocimientoId)
            .order('padre_id', { nullsFirst: true });

        if (fetchError) return { success: false, error: fetchError };
        if (!baseContents || baseContents.length === 0) return { success: true };

        // 2. Prepare manual ID range
        let currentNextId = await this.getNextUserContentId();
        const idMap = new Map<number, number>();

        try {
            // Process themes
            const themes = baseContents.filter(c => !c.padre_id);
            for (const theme of themes) {
                const newId = currentNextId++;
                const { error: themeError } = await supabase
                    .from('contenidos_usuario')
                    .insert({
                        id: newId,
                        propietario_id: session.user.id,
                        area_trabajo_id: areaTrabajoId,
                        origen_base_id: theme.id,
                        titulo: theme.titulo,
                        orden: theme.orden
                    });

                if (themeError) throw themeError;
                idMap.set(theme.id, newId);
            }

            // Process subthemes
            const subthemes = baseContents.filter(c => c.padre_id);
            for (const sub of subthemes) {
                const newId = currentNextId++;
                const newPadreId = idMap.get(sub.padre_id);
                const { error: subError } = await supabase
                    .from('contenidos_usuario')
                    .insert({
                        id: newId,
                        propietario_id: session.user.id,
                        area_trabajo_id: areaTrabajoId,
                        origen_base_id: sub.id,
                        padre_id: newPadreId,
                        titulo: sub.titulo,
                        orden: sub.orden
                    });

                if (subError) throw subError;
            }

            return { success: true };
        } catch (error) {
            console.error('Error in bulk copy:', error);
            return { success: false, error };
        }
    }
};

import { supabase } from '@/lib/supabase';
import { PDCData } from '@/context/wizard-context';

export interface PDC {
    id: string;
    gestion: number;
    trimestre: number;
    area_trabajo_id: string;
    fecha_inicio: string;
    fecha_fin: string;
    observaciones_generales: string;
    created_at: string;
    // Joined data
    area_trabajo?: {
        unidad_educativa: { nombre: string };
        area_conocimiento: { nombre: string };
    };
    semana_contenido?: {
        id: string;
        estado: string;
        contenido_usuario: {
            id: number;
            titulo: string;
        };
    }[];
}

export const PdcService = {
    /**
     * Saves a complete PDC including header, contents, moments, and criteria.
     */
    async savePdc(data: PDCData): Promise<{ success: boolean; pdcId?: string; error?: any }> {
        if (!data.areaId) return { success: false, error: 'No area ID provided' };

        try {
            // 1. Create the Main Planning Header (planificacion_semanal)
            const now = new Date();
            const { data: pdc, error: pdcError } = await supabase
                .from('planificacion_semanal')
                .insert({
                    area_trabajo_id: data.areaId,
                    gestion: now.getFullYear(),
                    trimestre: 1, // Logic could be added to detect current trimestre
                    mes: now.getMonth() + 1,
                    semana: 1,
                    fecha_inicio: now.toISOString(),
                    fecha_fin: now.toISOString(),
                    observaciones_generales: data.objetivoHolistico
                })
                .select()
                .single();

            if (pdcError) throw pdcError;

            // 2. Process each selected content
            for (const contentUserId of data.contenidosSeleccionados) {
                // a. Create semana_contenido
                const { data: semCont, error: semContError } = await supabase
                    .from('semana_contenido')
                    .insert({
                        planificacion_semanal_id: pdc.id,
                        contenido_usuario_id: contentUserId, // No longer need parseInt
                        estado: 'planificado'
                    })
                    .select()
                    .single();

                if (semContError) throw semContError;

                // b. Create Methodological Moments for this content
                if (data.momentos && data.momentos.length > 0) {
                    const momentsToInsert = data.momentos.map(m => ({
                        semana_contenido_id: semCont.id,
                        tipo: m.tipo,
                        descripcion: m.descripcion,
                        orden: m.orden
                    }));

                    const { error: momentsError } = await supabase
                        .from('momentos')
                        .insert(momentsToInsert);

                    if (momentsError) throw momentsError;
                }

                // c. Create Adaptaciones if provided
                if (data.adaptaciones?.descripcion) {
                    const { error: adaptError } = await supabase
                        .from('adaptaciones')
                        .insert({
                            semana_contenido_id: semCont.id,
                            tipo: 'Curricular',
                            descripcion: data.adaptaciones.descripcion,
                            recursos: data.adaptaciones.recursos,
                            criterios_adaptados: data.adaptaciones.criteriosAdaptados
                        });

                    if (adaptError) throw adaptError;
                }
            }

            // 3. Create General Evaluation Criteria linked to the Area
            if (data.criteriosEvaluacion && data.criteriosEvaluacion.length > 0) {
                const criteriaToInsert = data.criteriosEvaluacion.map((c, i) => ({
                    area_trabajo_id: data.areaId,
                    descripcion: c.descripcion,
                    dimension: c.dimension,
                    orden: i + 1
                }));

                const { error: critError } = await supabase
                    .from('criterios_evaluacion')
                    .insert(criteriaToInsert);

                if (critError) throw critError;
            }

            return { success: true, pdcId: pdc.id };
        } catch (error) {
            console.error('Error in PdcService.savePdc:', error);
            return { success: false, error };
        }
    },

    async getPDCs(userId: string): Promise<PDC[]> {
        const { data, error } = await supabase
            .from('planificacion_semanal')
            .select(`
                *,
                area_trabajo:areas_trabajo (
                    profesor_id,
                    unidad_educativa:unidades_educativas (nombre),
                    area_conocimiento:areas_conocimiento (nombre)
                ),
                semana_contenido (
                    id,
                    estado,
                    contenido_usuario:contenidos_usuario (
                        titulo
                    )
                )
            `)
            .eq('area_trabajo.profesor_id', userId)
            .order('created_at', { ascending: false });

        if (error) {
            console.error('Error fetching PDCs:', error);
            return [];
        }
        return data as unknown as PDC[];
    },

    async deletePDC(id: string): Promise<boolean> {
        const { error } = await supabase
            .from('planificacion_semanal')
            .delete()
            .eq('id', id);

        return !error;
    }
};

import { supabase } from '@/lib/supabase';

export interface UserProfile {
    id: string;
    email: string;
    nombres: string;
    apellidos: string;
    titulo?: string;
    celular?: string;
    foto_url?: string;
    creditos: number;
    roles?: string[];
    estado_completitud?: boolean;
}

export const ProfileService = {
    async getProfile(userId: string): Promise<UserProfile | null> {
        try {
            // 1. Get Profile Data from 'public' schema
            const { data: profile, error } = await supabase
                .from('perfiles')
                .select('*')
                .eq('id', userId)
                .maybeSingle();

            if (error) {
                console.error('Error fetching profile:', error);
                return null;
            }

            // If profile is null, it means no user was found, so return null early.
            if (!profile) {
                return null;
            }

            // 2. Get Roles
            const { data: rolesData, error: rolesError } = await supabase
                .from('perfil_roles')
                .select('rol_nombre')
                .eq('perfil_id', userId);

            if (rolesError) {
                console.error('Error fetching roles:', rolesError);
            }

            const roles = rolesData?.map((r: any) => r.rol_nombre) || [];

            return {
                ...profile,
                roles
            } as UserProfile;

        } catch (error) {
            console.error('Unexpected error in getProfile:', error);
            return null;
        }
    },

    async updateProfile(userId: string, updates: Partial<UserProfile>): Promise<{ success: boolean; error?: string }> {
        try {
            const { error } = await supabase
                .from('perfiles')
                .upsert({
                    id: userId, // Required for upsert
                    ...updates,
                    updated_at: new Date().toISOString()
                })
                .select();

            if (error) {
                console.error('Error updating profile:', error);
                return { success: false, error: error.message || 'Error de base de datos' };
            }
            return { success: true };
        } catch (error: any) {
            console.error('Unexpected error in updateProfile:', error);
            return { success: false, error: error.message || 'Error inesperado' };
        }
    }
};
